{
  "name": "UniTrade - College Marketplace",
  "description": "A vibrant and secure marketplace designed specifically for college students to buy and sell clothing, furniture, and other essentials within their campus community.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type Category = 'clothing' | 'furniture';

export interface Listing {
  id: string;
  title: string;
  price: number;
  category: Category;
  imageUrl: string;
  views: number;
  status: 'active' | 'sold';
  createdAt: string;
}

export interface User {
  name: string;
  handle: string;
  rating: number;
  reviewsCount: number;
  joinedDate: string;
  avatar: string;
}

export enum Tab {
  HOME = 'home',
  MESSAGES = 'messages',
  SELL = 'sell',
  PROFILE = 'profile'
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { Tab, Category } from './types';
import Navigation from './components/Navigation';
import SellFlow from './components/SellFlow';
import Profile from './components/Profile';
import Marketplace from './components/Marketplace';
import Messages from './components/Messages';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.SELL);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);

  const renderContent = () => {
    switch (activeTab) {
      case Tab.HOME:
        return <Marketplace />;
      case Tab.MESSAGES:
        return <Messages />;
      case Tab.SELL:
        return (
          <SellFlow 
            category={selectedCategory} 
            onSelectCategory={setSelectedCategory} 
            onCancel={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
          />
        );
      case Tab.PROFILE:
        return <Profile />;
      default:
        return <Marketplace />;
    }
  };

  return (
    <div className="min-h-screen pb-24 bg-gray-50">
      <div className="max-w-md mx-auto relative min-h-screen bg-white shadow-xl">
        {renderContent()}
        <Navigation activeTab={activeTab} onTabChange={(tab) => {
          setActiveTab(tab);
          if (tab !== Tab.SELL) setSelectedCategory(null);
        }} />
      </div>
    </div>
  );
};

export default App;

