import React, { useState } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isSupabaseConfigured) {
      onLogin(); // Just let them in if they haven't set up the keys yet
      return;
    }

    setIsLoading(true);
    setError(null);

    const { error: authError } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (authError) {
      const { error: signUpError } = await supabase.auth.signUp({
        email,
        password,
      });
      if (signUpError) setError(signUpError.message);
    }

    setIsLoading(false);
  };

  return (
    <div className="h-full bg-white flex flex-col px-8 py-16 animate-in fade-in duration-500">
      <div className="flex flex-col items-center justify-center mt-20 mb-12 text-center">
        <h1 className="text-6xl font-black text-[#FF8C42] tracking-tighter mb-10">
          Hucksta
        </h1>
        <div className="space-y-1">
          <h2 className="text-[#FF8C42] text-xl font-bold tracking-tight">Welcome back</h2>
          <p className="text-[#FFB380] text-sm font-medium">Log in or create an account</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-2">
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="UTD email"
            required
            className="w-full h-14 px-6 bg-gray-50 rounded-xl text-gray-800 border border-gray-100 outline-none focus:bg-white focus:ring-2 focus:ring-orange-200 transition-all placeholder-gray-300"
          />
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Password"
            required
            className="w-full h-14 px-6 bg-gray-50 rounded-xl text-gray-800 border border-gray-100 outline-none focus:bg-white focus:ring-2 focus:ring-orange-200 transition-all placeholder-gray-300"
          />
        </div>

        {error && <p className="text-xs text-red-500 px-1 font-medium">{error}</p>}

        <button
          type="submit"
          disabled={isLoading}
          className="w-full h-14 bg-[#FF8C42] text-white font-bold rounded-xl active:scale-[0.98] transition-all hover:bg-[#e67a35] shadow-lg shadow-orange-100 disabled:opacity-50"
        >
          {isLoading ? 'Processing...' : (isSupabaseConfigured ? 'Continue' : 'Enter as Guest')}
        </button>
      </form>

      <div className="flex items-center my-8">
        <div className="flex-1 h-[1px] bg-gray-100"></div>
        <span className="px-4 text-sm font-medium text-gray-400">or</span>
        <div className="flex-1 h-[1px] bg-gray-100"></div>
      </div>

      <div className="space-y-3">
        <button 
          onClick={onLogin}
          className="w-full h-14 bg-[#F2F2F2] flex items-center justify-center space-x-3 rounded-xl active:scale-[0.98] transition-all"
        >
          <span className="text-[#FF8C42] font-bold text-sm">Continue without Login</span>
        </button>
      </div>

      <div className="mt-auto mb-4 text-center">
        <p className="text-[11px] text-gray-400 leading-relaxed max-w-[280px] mx-auto">
          Built for the UTD Community
        </p>
      </div>
    </div>
  );
};

