    if (!itemName) return alert("Type a basic name first (e.g. 'green hoodie')");

    setIsEnhancing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `I am selling a clothing item on a college campus marketplace. 
        Basic Name: "${itemName}"
        Brand: "${brand}"
        Condition: "${condition}"

        Please provide a professional, catchy marketplace title and a 2-sentence description. 
        Format your response exactly like this:
        TITLE: [The Title]
        DESC: [The Description]`,
      });

      const text = response.text || '';
      const titleMatch = text.match(/TITLE:\s*(.*)/i);
      const descMatch = text.match(/DESC:\s*(.*)/i);

      if (titleMatch?.[1]) setItemName(titleMatch[1].trim());
      if (descMatch?.[1]) setDescription(descMatch[1].trim());
    } catch (err) {
      console.error("AI Error:", err);
      alert("Magic failed this time, but your listing is still great!");
    } finally {
      setIsEnhancing(false);
    }
  };

