import React, { useState } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface FurnitureListingFormProps {
  onBack: () => void;
  // Added missing props to fix type errors in SellFlow.tsx
  onSuccess?: () => void;
  session: any;
  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const mockPhotos = [
  'https://images.unsplash.com/photo-1524758631624-e2822e304c36?auto=format&fit=crop&q=80&w=600',
  'https://images.unsplash.com/photo-1592078615290-033ee584e267?auto=format&fit=crop&q=80&w=600',
  'https://images.unsplash.com/photo-1586023492125-27b2c045efd7?auto=format&fit=crop&q=80&w=600'
];

const FurnitureListingForm: React.FC<FurnitureListingFormProps> = ({ 
  onBack, 
  onSuccess, 
  session, 
  isDemoMode 
}) => {
  const [itemName, setItemName] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photoIndex, setPhotoIndex] = useState(-1);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];

  const handleAddPhoto = () => {
    setPhotoIndex((prev) => (prev + 1) % mockPhotos.length);
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photoIndex === -1) {
      return alert(photoIndex === -1 ? 'Please add at least one photo' : 'Please fill in required fields');
    }

    // Check demo mode before submitting
    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      // Use session from props for seller identity
      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          price: parseFloat(price),
          condition,
          category: 'Furniture',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: mockPhotos[photoIndex]
        }
      ]);

      if (error) throw error;
      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-emerald-600 p-6 flex items-start space-x-4">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full text-white active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
