      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20 no-scrollbar">
        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-700">Photos *</label>
          <div className="flex space-x-3">
            <button 
              onClick={handleAddPhoto}
              className={`w-32 h-32 rounded-3xl border-2 border-dashed flex flex-col items-center justify-center transition-all overflow-hidden ${
                photoIndex === -1 
                ? 'border-gray-200 bg-gray-50 text-gray-400 hover:bg-gray-100' 
                : 'border-emerald-500 bg-emerald-50 text-emerald-600'
              }`}
            >
              {photoIndex === -1 ? (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
                  <span className="text-[10px] font-bold uppercase tracking-tight">Add Photo</span>
                </>
              ) : (
                <img src={mockPhotos[photoIndex]} className="w-full h-full object-cover" alt="Preview" />
              )}
            </button>
          </div>
        </div>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Item Name *</label>
            <input 
              type="text" 
              value={itemName}
              onChange={(e) => setItemName(e.target.value)}
              placeholder="e.g. Ergonomic Office Chair" 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all" 
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-700">Price ($) *</label>
              <input 
                type="number" 
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                placeholder="0.00" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none" 
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-700">Pickup Location *</label>
              <select 
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 appearance-none outline-none"
              >
                {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Description</label>
            <textarea 
              rows={3}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Dimensions, assembly info, etc..." 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none resize-none"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Condition *</label>
            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button
                  key={c}
                  onClick={() => setCondition(c)}
                  className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all ${condition === c ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100 scale-105' : 'bg-gray-100 text-gray-500'}`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className={`w-full text-white font-black py-5 rounded-[2rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-widest text-sm mt-4 ${
            isDemoMode ? 'bg-gray-400 cursor-not-allowed' : 'bg-emerald-600 shadow-emerald-100 hover:bg-emerald-700'
          }`}
        >
          {isSubmitting ? 'Posting...' : isDemoMode ? 'Sign in to Post' : 'Post Furniture Item'}
        </button>
      </div>
    </div>
  );
};

