import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- 1. Create the Public Profiles table
create table profiles (
  id uuid references auth.users(id) primary key,
  full_name text,
  username text,
  avatar_url text
);

-- 2. Create the Listings table
create table listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid references auth.users(id)
);

-- 3. Automatic Profile Creation
create function public.handle_new_user()
returns trigger as $$
begin
  insert into public.profiles (id, full_name, username)
  values (new.id, new.raw_user_meta_data->>'full_name', new.email);
  return new;
end;
$$ language plpgsql security definer;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();

-- 4. Enable Security & Realtime
alter table listings enable row level security;
alter table profiles enable row level security;
create policy "Public viewable" on listings for select using (true);
create policy "Public viewable" on profiles for select using (true);
create policy "Users can insert own" on listings for insert with check (auth.uid() = seller_id);
alter publication supabase_realtime add table listings;
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('schema-db-changes')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select(`
          *,
          profiles:seller_id (full_name, username)
        `)
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else if (error.status === 401 || error.status === 403) {
          setErrorType('auth_error');
        } else {
          setErrorType('other');
        }
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err) {
      console.error('Fetch error:', err);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = isSupabaseConfigured && errorType === 'none'
    ? listings.filter(item => item.category === activeCategory)
    : [];

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
        <h1 className="text-5xl font-black text-white tracking-tight">Hucksta</h1>
        <div className="mt-2 flex items-center space-x-1 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
          <div className={`w-1.5 h-1.5 rounded-full ${errorType === 'none' ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></div>
          <span className="text-[10px] font-bold text-white uppercase tracking-widest">
            {errorType === 'none' ? 'Live Backend' : errorType === 'table_missing' ? 'Setup Needed' : 'Auth Error'}
          </span>
        </div>
      </div>

      {errorType === 'table_missing' ? (
        <div className="flex-1 p-6 flex flex-col">
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl flex flex-col items-center text-center space-y-4">
            <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 mb-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h2 className="text-xl font-black text-gray-800">Database Setup Required</h2>
            <p className="text-sm text-gray-500 font-medium">Please run the SQL in your Supabase Editor to enable Seller Profiles.</p>

            <div className="w-full text-left">
              <p className="text-[10px] font-bold text-orange-600 uppercase mb-2">1. Go to Supabase SQL Editor</p>
              <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[10px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar">
                {setupSQL}
              </pre>
            </div>

            <button 
              onClick={() => fetchListings()}
              className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all"
            >
              I've Run the SQL
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="pb-6 px-4">
            <div className="flex items-center pt-6 mb-6">
              <div className="relative flex-1">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-orange-400">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input 
                  type="text" 
                  placeholder="Search campus items..." 
                  className="w-full h-12 pl-12 pr-4 bg-white rounded-2xl text-sm font-medium focus:outline-none shadow-xl shadow-black/10 placeholder-gray-400"
                />
              </div>
            </div>

            <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
              {categories.map((cat) => (
                <button 
                  key={cat.name} 
                  onClick={() => setActiveCategory(cat.name)}
                  className={`flex items-center space-x-2 px-6 py-3 rounded-full whitespace-nowrap transition-all duration-200 shadow-sm border ${
                    activeCategory === cat.name 
                    ? 'bg-white text-orange-600 border-white' 
                    : 'bg-white/20 text-white border-white/30 backdrop-blur-md hover:bg-white/30'
                  }`}
                >
                  <span className="text-lg">{cat.icon}</span>
                  <span className="text-sm font-bold uppercase tracking-wide">{cat.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="flex-1 p-3 pb-24">
            {loading ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-4">
                <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
                <p className="text-white text-xs font-bold uppercase tracking-widest">Syncing with Campus...</p>
              </div>
            ) : displayedItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 px-10 text-center">
                <div className="bg-white/20 p-6 rounded-[2.5rem] backdrop-blur-md border border-white/30 mb-6">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white opacity-80" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
                  </svg>
                </div>
                <h3 className="text-white text-xl font-bold mb-2">No items here yet!</h3>
                <p className="text-white/70 text-sm font-medium">Be the first to list something in {activeCategory}!</p>
              </div>
            ) : (
              <div className="grid grid-cols-2 gap-3">
