import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';

interface ElectronicsListingFormProps {
  onBack: () => void;
  onSuccess?: () => void;
  session: any;
  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const ElectronicsListingForm: React.FC<ElectronicsListingFormProps> = ({ 
  onBack, 
  onSuccess, 
  session, 
  isDemoMode 
}) => {
  const [itemName, setItemName] = useState('');
  const [brand, setBrand] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, reader.result as string].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file);
    });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photos.length === 0) {
      return alert(photos.length === 0 ? 'Please upload at least one photo' : 'Please fill in required fields');
    }

    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      const imageUrlData = photos.length > 1 ? JSON.stringify(photos) : photos[0];

      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          brand,
          price: parseFloat(price),
          condition,
          category: 'Electronics',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;
      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-purple-600 p-6 flex items-start space-x-4">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full text-white active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h1 className="text-white text-xl font-semibold">List Electronics</h1>
          <p className="text-white/80 text-sm">Upload up to {MAX_PHOTOS} photos</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20 no-scrollbar">
        <div className="space-y-3">
          <label className="text-sm font-semibold text-gray-700 flex justify-between">
            <span>Photos *</span>
            <span className="text-[10px] text-gray-400">{photos.length}/{MAX_PHOTOS}</span>
          </label>

          <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
            {photos.map((photo, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={photo} className="w-28 h-28 rounded-2xl object-cover border border-gray-100" alt="Preview" />
                <button 
                  onClick={() => removePhoto(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg border-2 border-white active:scale-90 transition-transform"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            ))}

            {photos.length < MAX_PHOTOS && (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-28 h-28 rounded-2xl border-2 border-dashed border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 hover:bg-gray-100 hover:border-purple-200 transition-all flex-shrink-0"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span className="text-[10px] font-bold uppercase">Add Photo</span>
              </button>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            multiple 
            className="hidden" 
          />
        </div>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Item Name *</label>
            <input 
              type="text" 
              value={itemName}
              onChange={(e) => setItemName(e.target.value)}
              placeholder="e.g. MacBook Pro M1" 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none transition-all" 
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-700">Brand</label>
              <input 
                type="text" 
                value={brand}
                onChange={(e) => setBrand(e.target.value)}
                placeholder="Apple, etc." 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none" 
              />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-700">Price ($) *</label>
              <input 
                type="number" 
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                placeholder="0.00" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none" 
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Pickup Location *</label>
            <select 
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 appearance-none outline-none"
            >
              {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Description</label>
            <textarea 
              rows={3}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Specs, battery life, etc..." 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none resize-none"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Condition *</label>
            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button
                  key={c}
                  onClick={() => setCondition(c)}
                  className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all ${condition === c ? 'bg-purple-600 text-white shadow-lg shadow-purple-100 scale-105' : 'bg-gray-100 text-gray-500'}`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className={`w-full text-white font-black py-5 rounded-[2rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-widest text-sm mt-4 ${
            isDemoMode ? 'bg-gray-400 cursor-not-allowed' : 'bg-purple-600 shadow-purple-100 hover:bg-purple-700'
          }`}
        >
          {isSubmitting ? 'Posting...' : isDemoMode ? 'Sign in to Post' : 'Post Electronic Item'}
        </button>
      </div>
    </div>
  );
};

