              <p className="text-xs text-gray-400">Verified Student</p>
            </div>
          </div>

          {isOwner ? (
            <button 
              onClick={handleDelete}
              disabled={isDeleting}
              className="w-full bg-red-50 border border-red-100 py-4 rounded-2xl flex items-center justify-center space-x-2 shadow-sm active:scale-95 transition-all group"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-600 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              <span className="text-sm font-bold text-red-600 tracking-tight">
                {isDeleting ? 'Deleting...' : 'Delete Listing'}
              </span>
            </button>
          ) : (
            <button 
              onClick={onMessage}
              className="w-full bg-white border border-gray-100 py-4 rounded-2xl flex items-center justify-center space-x-2 shadow-sm active:scale-95 transition-all group"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
