import React, { useState, useEffect } from 'react';
import EditProfile from './EditProfile';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ProfileProps {
  session: any;
  onSelectItem?: (item: any) => void;
}

const Profile: React.FC<ProfileProps> = ({ session, onSelectItem }) => {
  const [activeTab, setActiveTab] = useState<'active' | 'sold' | 'favorites'>('active');
  const [isEditing, setIsEditing] = useState(false);
  const [myListings, setMyListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Extract name from metadata or fallback to email parts
  const fullName = session?.user?.user_metadata?.full_name || 
                   (session?.user?.email?.split('@')[0] || 'Hucksta User');

  const [userData] = useState({
    firstName: fullName.split(' ')[0],
    lastName: fullName.split(' ').slice(1).join(' '),
    username: session?.user?.email?.split('@')[0] || 'student',
    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.id || 'default'}`
  });

  useEffect(() => {
    fetchMyListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('user-listing-updates')
        .on('postgres_changes', { 
          event: '*', 
          schema: 'public', 
          table: 'listings',
          filter: `seller_id=eq.${session?.user?.id}`
        }, () => {
          fetchMyListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, [session?.user?.id]);

  const fetchMyListings = async () => {
    if (!isSupabaseConfigured || !session?.user?.id) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .eq('seller_id', session.user.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setMyListings(data);
    } catch (err) {
      console.error('Error fetching my listings:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    if (isSupabaseConfigured) {
      await supabase.auth.signOut();
    } else {
      window.location.reload(); 
    }
  };

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  if (isEditing) {
    return (
      <EditProfile 
        user={userData} 
        onBack={() => setIsEditing(false)} 
      />
    );
  }

  return (
    <div className="h-full bg-white flex flex-col">
      {/* Profile Header */}
      <div className="relative h-64 bg-gradient-to-br from-orange-500 via-orange-600 to-emerald-600 p-6 flex flex-col justify-end">
        <button 
          onClick={handleLogout}
          className="absolute top-12 right-6 bg-white/20 p-2 rounded-xl text-white backdrop-blur-md hover:bg-white/30 transition-colors"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
          </svg>
        </button>

        <div className="flex items-center space-x-4">
          <div className="relative">
            <img 
              src={userData.avatar} 
              alt={userData.firstName} 
              className="w-24 h-24 rounded-3xl border-4 border-white object-cover shadow-lg bg-orange-100"
            />
          </div>
          <div className="text-white">
            <h2 className="text-2xl font-bold truncate max-w-[200px]">{fullName}</h2>
            <p className="text-white/80 font-medium">@{userData.username}</p>
          </div>
        </div>
      </div>

      <div className="p-4 bg-gray-50 border-b border-gray-100">
        <div className="flex items-center justify-between bg-white p-3 rounded-2xl shadow-sm">
          <div className="flex items-center space-x-3">
            <div className={`w-3 h-3 rounded-full ${isSupabaseConfigured ? 'bg-emerald-500 animate-pulse' : 'bg-orange-500'}`}></div>
            <div>
              <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Connection</p>
              <p className={`text-xs font-bold ${isSupabaseConfigured ? 'text-emerald-600' : 'text-orange-600'}`}>
                {isSupabaseConfigured ? 'Supabase Connected' : 'Demo Mode (Offline)'}
              </p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Active Listings</p>
            <p className="text-xs font-bold text-gray-800">{myListings.length}</p>
          </div>
        </div>
      </div>

      <div className="flex border-b border-gray-100 px-2">
        <button onClick={() => setActiveTab('active')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'active' ? 'text-orange-600' : 'text-gray-400'}`}>
          Active
          {activeTab === 'active' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
        <button onClick={() => setActiveTab('sold')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'sold' ? 'text-orange-600' : 'text-gray-400'}`}>
          Sold
          {activeTab === 'sold' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
        <button onClick={() => setActiveTab('favorites')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'favorites' ? 'text-orange-600' : 'text-gray-400'}`}>
          Favorites
          {activeTab === 'favorites' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-4">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest">Loading Items...</p>
          </div>
        ) : activeTab === 'active' && myListings.length > 0 ? (
          <div className="grid grid-cols-2 gap-3">
            {myListings.map((item) => (
              <div 
                key={item.id} 
                onClick={() => onSelectItem?.(item)}
                className="bg-white rounded-[2rem] p-1.5 border border-gray-100 shadow-sm flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer"
              >
                <div className="relative aspect-[4/5] rounded-[1.75rem] overflow-hidden mb-2">
                  <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                  <div className="absolute top-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg shadow-sm border border-gray-100">
                    <span className="text-[10px] font-black text-orange-600">${item.price}</span>
                  </div>
                </div>
                <div className="px-2 pb-2">
                  <h3 className="font-bold text-gray-800 text-[10px] leading-tight line-clamp-2 h-6 mb-1">{item.title}</h3>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-12 text-gray-400">
            <div className="bg-gray-50 p-6 rounded-[2.5rem] mb-6">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
              </svg>
            </div>
            <p className="font-bold text-sm text-gray-500">No {activeTab} items found</p>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Start by listing something for sale!</p>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 bg-white sticky bottom-0 flex space-x-3">
        <button 
          onClick={() => setIsEditing(true)}
          className="flex-1 bg-orange-600 text-white font-bold py-4 rounded-2xl flex items-center justify-center space-x-2 shadow-lg shadow-orange-100 active:scale-[0.98] transition-all"
        >
          <span>Edit Profile</span>
        </button>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';

interface ClothingListingFormProps {
  onBack: () => void;
  onSuccess?: () => void;
  session: any;
  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const ClothingListingForm: React.FC<ClothingListingFormProps> = ({ onBack, onSuccess, session, isDemoMode }) => {
  const [itemName, setItemName] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, reader.result as string].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file);
    });
    // Reset input so the same file can be picked again if deleted
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photos.length === 0) {
      return alert(photos.length === 0 ? 'Please upload at least one photo' : 'Please fill in required fields');
    }

    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      // Store photos as a JSON string to support multiple images in the text column
      const imageUrlData = photos.length > 1 ? JSON.stringify(photos) : photos[0];

      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          price: parseFloat(price),
          condition,
          category: 'Clothing',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;

      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-orange-600 p-6 flex items-start space-x-4 text-white">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h1 className="text-xl font-semibold">List Clothing</h1>
          <p className="text-white/80 text-sm">Upload up to {MAX_PHOTOS} photos of your item</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20 no-scrollbar">
        <div className="space-y-3">
          <label className="text-sm font-semibold text-gray-700 flex justify-between">
            <span>Photos *</span>
            <span className="text-[10px] text-gray-400">{photos.length}/{MAX_PHOTOS}</span>
          </label>

          <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
            {photos.map((photo, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={photo} className="w-28 h-28 rounded-2xl object-cover border border-gray-100" alt="Preview" />
                <button 
                  onClick={() => removePhoto(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg border-2 border-white active:scale-90 transition-transform"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            ))}

            {photos.length < MAX_PHOTOS && (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-28 h-28 rounded-2xl border-2 border-dashed border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 hover:bg-gray-100 hover:border-orange-200 transition-all flex-shrink-0"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span className="text-[10px] font-bold uppercase">Add Photo</span>
              </button>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            multiple 
            className="hidden" 
          />
        </div>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Item Name *</label>
            <input 
              type="text" 
              value={itemName}
              onChange={(e) => setItemName(e.target.value)}
              placeholder="e.g. UTD Hoodie" 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all" 
            />
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Price ($) *</label>
            <input 
              type="number" 
              value={price}
              onChange={(e) => setPrice(e.target.value)}
              placeholder="0.00" 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none" 
            />
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Pickup Location *</label>
            <select 
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 appearance-none outline-none"
            >
              {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Description</label>
            <textarea 
              rows={3}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Tell other students about this item..." 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none resize-none"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700">Condition *</label>
            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button
                  key={c}
                  onClick={() => setCondition(c)}
                  className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all ${condition === c ? 'bg-orange-600 text-white shadow-lg shadow-orange-100 scale-105' : 'bg-gray-100 text-gray-500'}`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className={`w-full text-white font-black py-5 rounded-[2rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-widest text-sm mt-4 ${
            isDemoMode ? 'bg-gray-400 cursor-not-allowed' : 'bg-orange-600 shadow-orange-100 hover:bg-orange-700'
          }`}
        >
          {isSubmitting ? 'Posting...' : isDemoMode ? 'Sign in to Post' : 'Post Clothing Item'}
        </button>
      </div>
    </div>
  );
};

export default ClothingListingForm;

