          image_url: imageUrlData
        }
      ]);

      if (error) throw error;
      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-purple-600 p-6 flex items-start space-x-4">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full text-white active:scale-90 transition-transform">
