import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- Run this in your Supabase SQL Editor:

-- 1. Create Listings table
create table listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid references auth.users(id)
);

-- 2. Create Profiles table for seller info
create table profiles (
  id uuid references auth.users on delete cascade primary key,
  full_name text
);

-- 3. Enable Realtime
alter publication supabase_realtime add table listings;

-- 4. Enable RLS (Security)
alter table listings enable row level security;
create policy "Public listings are viewable by everyone" on listings for select using (true);
create policy "Users can insert their own listings" on listings for insert with check (auth.uid() = seller_id);
create policy "Users can delete their own listings" on listings for delete using (auth.uid() = seller_id);

alter table profiles enable row level security;
create policy "Profiles are viewable by everyone" on profiles for select using (true);
create policy "Users can update own profile" on profiles for update using (auth.uid() = id);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('schema-db-changes')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*, profiles:seller_id(full_name)')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else if (error.status === 401 || error.status === 403) {
          setErrorType('auth_error');
        } else {
          setErrorType('other');
          setErrorMsg(error.message || JSON.stringify(error));
        }
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = isSupabaseConfigured && errorType === 'none'
    ? listings.filter(item => item.category === activeCategory)
    : [];

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
        <h1 className="text-5xl font-black text-white tracking-tight">Hucksta</h1>
        <div className="mt-2 flex items-center space-x-1 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
          <div className={`w-1.5 h-1.5 rounded-full ${errorType === 'none' ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></div>
          <span className="text-[10px] font-bold text-white uppercase tracking-widest">
            {errorType === 'none' ? 'Live Backend' : errorType === 'table_missing' ? 'Setup Needed' : 'Error'}
          </span>
        </div>
      </div>

      {errorType !== 'none' && errorType !== 'table_missing' && (
        <div className="mx-4 p-4 bg-red-500/20 backdrop-blur border border-red-500/30 rounded-2xl text-white text-[10px] font-bold uppercase mb-4">
          Error: {errorMsg || 'Failed to connect to campus database.'}
        </div>
      )}

      {errorType === 'table_missing' ? (
        <div className="flex-1 p-6 flex flex-col">
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl flex flex-col items-center text-center space-y-4">
            <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 mb-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h2 className="text-xl font-black text-gray-800">Database Setup Required</h2>
            <p className="text-sm text-gray-500 font-medium">Please create the <code className="bg-gray-100 px-1 rounded font-bold">listings</code> and <code className="bg-gray-100 px-1 rounded font-bold">profiles</code> tables.</p>

            <div className="w-full text-left">
              <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[10px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar">
                {setupSQL}
              </pre>
            </div>

            <button 
              onClick={() => fetchListings()}
              className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all"
            >
              I've Run the SQL
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="pb-6 px-4">
            <div className="flex items-center pt-6 mb-6">
              <div className="relative flex-1">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-orange-400">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input 
                  type="text" 
                  placeholder="Search campus items..." 
                  className="w-full h-12 pl-12 pr-4 bg-white rounded-2xl text-sm font-medium focus:outline-none shadow-xl shadow-black/10 placeholder-gray-400"
                />
              </div>
            </div>

            <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
              {categories.map((cat) => (
                <button 
                  key={cat.name} 
                  onClick={() => setActiveCategory(cat.name)}
                  className={`flex items-center space-x-2 px-6 py-3 rounded-full whitespace-nowrap transition-all duration-200 shadow-sm border ${
                    activeCategory === cat.name 
                    ? 'bg-white text-orange-600 border-white' 
                    : 'bg-white/20 text-white border-white/30 backdrop-blur-md hover:bg-white/30'
                  }`}
                >
                  <span className="text-lg">{cat.icon}</span>
                  <span className="text-sm font-bold uppercase tracking-wide">{cat.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="flex-1 p-3 pb-24">
            {loading ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-4">
                <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
                <p className="text-white text-xs font-bold uppercase tracking-widest">Syncing with Campus...</p>
              </div>
            ) : displayedItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 px-10 text-center">
                <div className="bg-white/20 p-6 rounded-[2.5rem] backdrop-blur-md border border-white/30 mb-6">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white opacity-80" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
                  </svg>
                </div>
                <h3 className="text-white text-xl font-bold mb-2">No items here yet!</h3>
              </div>
            ) : (
              <div className="grid grid-cols-2 gap-3">
                {displayedItems.map((item: any) => (
                  <div 
                    key={item.id} 
                    onClick={() => onSelectItem?.(item)}
                    className="bg-white rounded-[2rem] p-1.5 shadow-xl flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer"
                  >
                    <div className="relative aspect-[4/5] rounded-[1.75rem] overflow-hidden mb-2">
                      <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                      <div className={`absolute top-2 left-2 px-2.5 py-1 rounded-full text-[10px] font-bold text-white shadow-md bg-emerald-600`}>
                        {item.condition}
                      </div>
                    </div>

                    <div className="px-2 pb-2">
                      <h3 className="font-bold text-gray-800 text-xs leading-tight mb-1 line-clamp-2 h-8">
                        {item.title}
                      </h3>
                      {/* Show Brand first, fallback to Seller Name */}
                      <p className="text-[10px] text-gray-400 font-bold mb-1 truncate uppercase tracking-tighter">
                        {item.brand || item.profiles?.full_name || 'Hucksta Seller'}
                      </p>
                      <div className="flex items-center text-emerald-600 mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 mr-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                        </svg>
                        <span className="text-[9px] font-bold line-clamp-1">{item.location}</span>
                      </div>
                      <div className="flex justify-between items-end">
                        <p className="text-orange-600 font-black text-lg">${item.price}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default Marketplace;

import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';

interface ClothingListingFormProps {
  onBack: () => void;
  onSuccess?: () => void;
  session: any;
  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const ClothingListingForm: React.FC<ClothingListingFormProps> = ({ onBack, onSuccess, session, isDemoMode }) => {
  const [itemName, setItemName] = useState('');
  const [brand, setBrand] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, reader.result as string].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file as any);
    });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photos.length === 0) {
      return alert(photos.length === 0 ? 'Please upload at least one photo' : 'Please fill in required fields');
    }

    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      const imageUrlData = photos.length > 1 ? JSON.stringify(photos) : photos[0];

      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          brand,
          price: parseFloat(price),
          condition,
          category: 'Clothing',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;

      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-orange-600 p-6 flex items-start space-x-4 text-white">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h1 className="text-xl font-semibold">List Clothing</h1>
          <p className="text-white/80 text-sm">Upload up to {MAX_PHOTOS} photos of your item</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20 no-scrollbar">
        <div className="space-y-3">
          <label className="text-sm font-semibold text-gray-700 flex justify-between">
            <span>Photos *</span>
            <span className="text-[10px] text-gray-400">{photos.length}/{MAX_PHOTOS}</span>
          </label>

          <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
            {photos.map((photo, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={photo} className="w-28 h-28 rounded-2xl object-cover border border-gray-100" alt="Preview" />
                <button 
                  onClick={() => removePhoto(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg border-2 border-white active:scale-90 transition-transform"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            ))}

            {photos.length < MAX_PHOTOS && (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-28 h-28 rounded-2xl border-2 border-dashed border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 hover:bg-gray-100 hover:border-orange-200 transition-all flex-shrink-0"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 mb-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span className="text-[10px] font-bold uppercase">Add Photo</span>
              </button>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            multiple 
            className="hidden" 
          />
        </div>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-700">Item Name *</label>
            <input 
              type="text" 
              value={itemName}
              onChange={(e) => setItemName(e.target.value)}
