  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const FurnitureListingForm: React.FC<FurnitureListingFormProps> = ({ 
  onBack, 
  onSuccess, 
  session, 
  isDemoMode 
}) => {
  const [itemName, setItemName] = useState('');
  const [brand, setBrand] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, reader.result as string].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file as any);
    });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photos.length === 0) {
      return alert(photos.length === 0 ? 'Please upload at least one photo' : 'Please fill in required fields');
    }

    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      const imageUrlData = photos.length > 1 ? JSON.stringify(photos) : photos[0];

      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          brand,
          price: parseFloat(price),
          condition,
          category: 'Furniture',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;
      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong. Did you run the SQL in Supabase?');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
