              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" />
              </svg>
            </div>
            <h2 className="text-xl font-black text-gray-800">Database Repair Tool</h2>
            <p className="text-sm text-gray-500 font-medium">To fix the seller name relationship, copy this entire script and run it in your Supabase SQL Editor:</p>

            <div className="w-full text-left">
              <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[10px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar border border-white/10 shadow-inner select-all">
