            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img 
            src={photos[currentPhotoIdx]} 
            alt={item.title} 
            className="w-full h-full object-contain mix-blend-multiply transition-all duration-300"
          />

          {photos.length > 1 && (
            <>
              <button 
                onClick={handlePrev}
                className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-r-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
                </svg>
              </button>
              <button 
                onClick={handleNext}
                className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-l-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </button>
            </>
          )}
        </div>

        {/* Pagination Dots */}
        {photos.length > 0 && (
          <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center space-y-1.5 z-20">
            <div className="flex space-x-1.5">
              {photos.map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${i === currentPhotoIdx ? 'bg-orange-500 w-4' : 'bg-gray-300'}`} 
                />
              ))}
            </div>
            <span className="text-[9px] font-black text-gray-400 tracking-widest uppercase">{currentPhotoIdx + 1}/{photos.length}</span>
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
            <div className="flex items-center space-x-1.5">
              {item.brand && (
                <span className="text-sm font-bold text-orange-600 uppercase tracking-tighter">{item.brand}</span>
              )}
              <div className="bg-emerald-100 p-0.5 rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-emerald-600" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
              </div>
            </div>
          </div>
          <div className="border-2 border-orange-100 rounded-[1.25rem] px-4 py-2 flex items-center justify-center bg-white shadow-sm">
            <span className="text-xl font-black text-orange-600">${item.price}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-4">
          <div className="bg-orange-50/50 border border-orange-100/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 mb-1">Condition</p>
