        </div>

        <div className="bg-emerald-50/30 border border-emerald-100 rounded-[1.5rem] p-4 mb-8 flex items-center space-x-3">
          <div className="bg-orange-100 p-2.5 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <div>
            <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400">Pickup Location</p>
            <p className="text-sm font-bold text-orange-600">{item.location}</p>
          </div>
        </div>

        {item.description && (
          <div className="mb-8">
            <p className="text-[11px] uppercase tracking-widest font-bold text-gray-400 mb-2">Description</p>
            <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{item.description}</p>
          </div>
        )}

        <div className="bg-gray-50/50 border border-gray-100 rounded-[2rem] p-5 space-y-5">
          <p className="text-[11px] uppercase tracking-widest font-bold text-gray-400">
            {isOwner ? 'Your Listing' : 'Seller Information'}
          </p>
          <div className="flex items-center space-x-4">
            <div className="relative">
              <img 
                src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${item.seller_id}`} 
