import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- 1. CLEAN SLATE: Remove old tables
drop table if exists public.listings;
drop table if exists public.profiles;

-- 2. CREATE PROFILES: This stores user display names
create table public.profiles (
  id uuid references auth.users on delete cascade primary key,
  full_name text,
  updated_at timestamp with time zone default now()
);

-- 3. CREATE LISTINGS: Linked to profiles via seller_id
create table public.listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null references public.profiles(id) on delete cascade
);

-- 4. AUTOMATION: Sync new signups to profiles
create or replace function public.handle_new_user()
returns trigger as $$
begin
  insert into public.profiles (id, full_name)
  values (new.id, coalesce(new.raw_user_meta_data->>'full_name', new.email));
  return new;
end;
$$ language plpgsql security definer;

drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();

-- 5. BACKFILL: Create profiles for any users already in the system
insert into public.profiles (id, full_name)
select id, coalesce(raw_user_meta_data->>'full_name', email)
from auth.users
on conflict (id) do nothing;

-- 6. SECURITY: Enable RLS
alter table listings enable row level security;
alter table profiles enable row level security;

create policy "Public view listings" on listings for select using (true);
create policy "Users add listings" on listings for insert with check (auth.uid() = seller_id);
create policy "Users delete listings" on listings for delete using (auth.uid() = seller_id);
create policy "Public view profiles" on profiles for select using (true);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-live')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      // Explicit Join Hint (!seller_id) is mandatory when linking profiles to listings
      const { data, error } = await supabase
        .from('listings')
        .select('*, profiles!seller_id(full_name)')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else if (error.status === 401 || error.status === 403) {
          setErrorType('auth_error');
        } else if (error.message.includes('relationship')) {
          setErrorMsg('Relationship Error: The connection between Items and Sellers is broken.');
          setErrorType('other');
        } else {
          setErrorType('other');
          setErrorMsg(error.message);
        }
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
        setErrorMsg('');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = isSupabaseConfigured && errorType === 'none'
    ? listings.filter(item => item.category === activeCategory)
    : [];

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
