import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- SIMPLE SETUP: Create the listings table
-- Run this in your Supabase SQL Editor

create table if not exists public.listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null default auth.uid()
);

-- Enable Security
alter table listings enable row level security;

-- Policies
create policy "Anyone can view listings" on listings for select using (true);
create policy "Users can add their own items" on listings for insert with check (auth.uid() = seller_id);
create policy "Users can delete their own items" on listings for delete using (auth.uid() = seller_id);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-updates')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      // Simplified query - no joins, no complications
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else {
          setErrorType('other');
          setErrorMsg(error.message);
        }
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = isSupabaseConfigured && errorType === 'none'
    ? listings.filter(item => item.category === activeCategory)
    : [];

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
        <h1 className="text-5xl font-black text-white tracking-tight">Hucksta</h1>
        <div className="mt-2 flex items-center space-x-1 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
          <div className={`w-1.5 h-1.5 rounded-full ${errorType === 'none' ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></div>
          <span className="text-[10px] font-bold text-white uppercase tracking-widest">
            {errorType === 'none' ? 'Campus Live' : 'Setup Required'}
          </span>
        </div>
      </div>

      {errorType === 'table_missing' ? (
        <div className="flex-1 p-6 flex flex-col">
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl flex flex-col items-center text-center space-y-4">
            <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 mb-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
            </div>
            <h2 className="text-xl font-black text-gray-800">Database Connection</h2>
            <p className="text-xs text-gray-500 font-medium leading-relaxed">
              Your marketplace table hasn't been created yet. Copy this script into your Supabase SQL Editor to go live.
            </p>

            <div className="w-full text-left">
              <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[10px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar border border-white/10 shadow-inner select-all">
                {setupSQL}
              </pre>
            </div>

            <button 
              onClick={() => {
                setLoading(true);
                fetchListings();
              }}
              className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all shadow-xl shadow-orange-100 uppercase tracking-widest text-xs"
            >
              Refresh Feed
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="pb-6 px-4">
            <div className="flex items-center pt-6 mb-6">
              <div className="relative flex-1">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-orange-400">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input 
                  type="text" 
                  placeholder="Search campus items..." 
                  className="w-full h-12 pl-12 pr-4 bg-white rounded-2xl text-sm font-medium focus:outline-none shadow-xl shadow-black/10 placeholder-gray-400"
                />
              </div>
            </div>

            <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
              {categories.map((cat) => (
                <button 
                  key={cat.name} 
                  onClick={() => setActiveCategory(cat.name)}
                  className={`flex items-center space-x-2 px-6 py-3 rounded-full whitespace-nowrap transition-all duration-200 shadow-sm border ${
                    activeCategory === cat.name 
                    ? 'bg-white text-orange-600 border-white' 
                    : 'bg-white/20 text-white border-white/30 backdrop-blur-md hover:bg-white/30'
                  }`}
                >
                  <span className="text-lg">{cat.icon}</span>
                  <span className="text-sm font-bold uppercase tracking-wide">{cat.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="flex-1 p-3 pb-24">
            {loading ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-4">
                <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
                <p className="text-white text-xs font-bold uppercase tracking-widest">Checking Campus...</p>
              </div>
            ) : displayedItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 px-10 text-center">
                <div className="bg-white/20 p-6 rounded-[2.5rem] backdrop-blur-md border border-white/30 mb-6">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white opacity-80" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
                  </svg>
                </div>
                <h3 className="text-white text-xl font-bold mb-2">No items listed</h3>
                <p className="text-white/60 text-xs font-medium uppercase tracking-wider">Be the first to list something!</p>
              </div>
            ) : (
              <div className="grid grid-cols-2 gap-3">
                {displayedItems.map((item: any) => (
                  <div 
                    key={item.id} 
                    onClick={() => onSelectItem?.(item)}
                    className="bg-white rounded-[2rem] p-1.5 shadow-xl flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer"
                  >
                    <div className="relative aspect-[4/5] rounded-[1.75rem] overflow-hidden mb-2">
                      <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                      <div className={`absolute top-2 left-2 px-2.5 py-1 rounded-full text-[10px] font-bold text-white shadow-md bg-emerald-600`}>
                        {item.condition}
                      </div>
                    </div>

                    <div className="px-2 pb-2">
                      <h3 className="font-bold text-gray-800 text-xs leading-tight mb-1 line-clamp-2 h-8">
                        {item.title}
                      </h3>
                      <p className="text-[10px] text-gray-400 font-bold mb-1 truncate uppercase tracking-tighter">
                        {item.brand || item.category}
                      </p>
                      <div className="flex items-center text-emerald-600 mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 mr-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                        </svg>
                        <span className="text-[9px] font-bold line-clamp-1">{item.location}</span>
                      </div>
                      <div className="flex justify-between items-end">
                        <p className="text-orange-600 font-black text-lg">${Number(item.price).toFixed(2)}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default Marketplace;

import React, { useState, useMemo } from 'react';
import { supabase } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  onBack: () => void;
  onMessage: () => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  const isOwner = session?.user?.id === item.seller_id;

  // Parse photos if they are stored as a JSON array
  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => {
    setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  };

  const handlePrev = () => {
    setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);
  };

  const handleDelete = async () => {
    if (!window.confirm('Are you sure you want to delete this listing? This action cannot be undone.')) {
      return;
    }

    setIsDeleting(true);
    try {
      const { error } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id);

      if (error) throw error;

      onBack();
    } catch (err: any) {
      console.error('Delete error:', err.message || err);
      alert('Failed to delete listing. Please try again.');
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      {/* Top Media Section */}
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button 
          onClick={onBack}
          className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100 active:scale-90 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img 
            src={photos[currentPhotoIdx]} 
            alt={item.title} 
            className="w-full h-full object-contain mix-blend-multiply transition-all duration-300"
          />

          {photos.length > 1 && (
            <>
              <button 
                onClick={handlePrev}
                className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-r-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
                </svg>
              </button>
              <button 
                onClick={handleNext}
                className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-l-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </button>
            </>
          )}
        </div>

        {/* Pagination Dots */}
        {photos.length > 0 && (
          <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center space-y-1.5 z-20">
            <div className="flex space-x-1.5">
              {photos.map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${i === currentPhotoIdx ? 'bg-orange-500 w-4' : 'bg-gray-300'}`} 
                />
              ))}
            </div>
            <span className="text-[9px] font-black text-gray-400 tracking-widest uppercase">{currentPhotoIdx + 1}/{photos.length}</span>
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
