import React, { useState, useEffect } from 'react';
import EditProfile from './EditProfile';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ProfileProps {
  session: any;
  onSelectItem?: (item: any) => void;
}

const Profile: React.FC<ProfileProps> = ({ session, onSelectItem }) => {
  const [activeTab, setActiveTab] = useState<'active' | 'sold' | 'favorites'>('active');
  const [isEditing, setIsEditing] = useState(false);
  const [myListings, setMyListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Extract name from metadata or fallback to email parts
  const fullName = session?.user?.user_metadata?.full_name || 
                   (session?.user?.email?.split('@')[0] || 'Hucksta User');

  const [userData] = useState({
    firstName: fullName.split(' ')[0],
    lastName: fullName.split(' ').slice(1).join(' '),
    username: session?.user?.email?.split('@')[0] || 'student',
    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.id || 'default'}`
  });

  useEffect(() => {
    fetchMyListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('user-listing-updates')
        .on('postgres_changes', { 
          event: '*', 
          schema: 'public', 
          table: 'listings',
          filter: `seller_id=eq.${session?.user?.id}`
        }, () => {
          fetchMyListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, [session?.user?.id]);

  const fetchMyListings = async () => {
    if (!isSupabaseConfigured || !session?.user?.id) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .eq('seller_id', session.user.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setMyListings(data);
    } catch (err) {
      console.error('Error fetching my listings:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    if (isSupabaseConfigured) {
      await supabase.auth.signOut();
    } else {
      window.location.reload(); 
    }
  };

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  if (isEditing) {
    return (
      <EditProfile 
        user={userData} 
        onBack={() => setIsEditing(false)} 
      />
    );
  }

  return (
    <div className="h-full bg-white flex flex-col">
      {/* Profile Header */}
      <div className="relative h-64 bg-gradient-to-br from-orange-500 via-orange-600 to-emerald-600 p-6 flex flex-col justify-end">
        <button 
          onClick={handleLogout}
          className="absolute top-12 right-6 bg-white/20 p-2 rounded-xl text-white backdrop-blur-md hover:bg-white/30 transition-colors"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
          </svg>
        </button>

        <div className="flex items-center space-x-4">
          <div className="relative">
            <img 
              src={userData.avatar} 
              alt={userData.firstName} 
              className="w-24 h-24 rounded-3xl border-4 border-white object-cover shadow-lg bg-orange-100"
            />
          </div>
          <div className="text-white">
            <h2 className="text-2xl font-bold truncate max-w-[200px]">{fullName}</h2>
            <p className="text-white/80 font-medium">@{userData.username}</p>
          </div>
        </div>
      </div>

      <div className="p-4 bg-gray-50 border-b border-gray-100">
        <div className="flex items-center justify-between bg-white p-3 rounded-2xl shadow-sm">
          <div className="flex items-center space-x-3">
            <div className={`w-3 h-3 rounded-full ${isSupabaseConfigured ? 'bg-emerald-500 animate-pulse' : 'bg-orange-500'}`}></div>
            <div>
              <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Connection</p>
              <p className={`text-xs font-bold ${isSupabaseConfigured ? 'text-emerald-600' : 'text-orange-600'}`}>
                {isSupabaseConfigured ? 'Supabase Connected' : 'Demo Mode (Offline)'}
              </p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Active Listings</p>
            <p className="text-xs font-bold text-gray-800">{myListings.length}</p>
          </div>
        </div>
      </div>

      <div className="flex border-b border-gray-100 px-2">
        <button onClick={() => setActiveTab('active')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'active' ? 'text-orange-600' : 'text-gray-400'}`}>
          Active
          {activeTab === 'active' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
        <button onClick={() => setActiveTab('sold')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'sold' ? 'text-orange-600' : 'text-gray-400'}`}>
          Sold
          {activeTab === 'sold' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
        <button onClick={() => setActiveTab('favorites')} className={`flex-1 py-4 text-[11px] font-bold uppercase tracking-wider relative transition-colors ${activeTab === 'favorites' ? 'text-orange-600' : 'text-gray-400'}`}>
          Favorites
          {activeTab === 'favorites' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-orange-600 rounded-t-full"></div>}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar p-4">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest">Loading Items...</p>
          </div>
        ) : activeTab === 'active' && myListings.length > 0 ? (
          <div className="grid grid-cols-2 gap-3">
            {myListings.map((item) => (
              <div 
                key={item.id} 
                onClick={() => onSelectItem?.(item)}
                className="bg-white rounded-[2rem] p-1.5 border border-gray-100 shadow-sm flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer"
              >
                <div className="relative aspect-[4/5] rounded-[1.75rem] overflow-hidden mb-2">
                  <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                  <div className="absolute top-2 right-2 bg-white/90 backdrop-blur px-2 py-1 rounded-lg shadow-sm border border-gray-100">
                    <span className="text-[10px] font-black text-orange-600">${Number(item.price).toFixed(2)}</span>
                  </div>
                </div>
                <div className="px-2 pb-2">
                  <h3 className="font-bold text-gray-800 text-[10px] leading-tight line-clamp-2 h-6 mb-1">{item.title}</h3>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-12 text-gray-400">
            <div className="bg-gray-50 p-6 rounded-[2.5rem] mb-6">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
              </svg>
            </div>
            <p className="font-bold text-sm text-gray-500">No {activeTab} items found</p>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-1">Start by listing something for sale!</p>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 bg-white sticky bottom-0 flex space-x-3">
        <button 
          onClick={() => setIsEditing(true)}
          className="flex-1 bg-orange-600 text-white font-bold py-4 rounded-2xl flex items-center justify-center space-x-2 shadow-lg shadow-orange-100 active:scale-[0.98] transition-all"
        >
          <span>Edit Profile</span>
        </button>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState, useEffect } from 'react';
import { Tab, Category } from './types';
import Navigation from './components/Navigation';
import SellFlow from './components/SellFlow';
import Profile from './components/Profile';
import Marketplace from './components/Marketplace';
import Messages from './components/Messages';
import ItemDetail from './components/ItemDetail';
import Login from './components/Login';
import { supabase, isSupabaseConfigured } from './lib/supabase';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [viewingItem, setViewingItem] = useState<any>(null);
  const [isDemoMode, setIsDemoMode] = useState(!isSupabaseConfigured);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    // Check initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) setIsDemoMode(false);
      else setIsDemoMode(!isSupabaseConfigured);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleDemoLogin = () => {
    setIsDemoMode(true);
    setSession({ user: { email: 'demo@utdallas.edu', id: 'demo-user' } });
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-orange-600 font-bold animate-pulse tracking-tighter text-xl">Hucksta</p>
        </div>
      </div>
    );
  }

  if (!session) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white shadow-2xl rounded-[3rem] overflow-hidden min-h-[852px]">
          <Login onLogin={handleDemoLogin} />
          {!isSupabaseConfigured && (
            <div className="px-8 pb-8 -mt-8 text-center">
              <p className="text-[10px] text-gray-400 mb-2 italic">Backend not connected yet.</p>
              <button 
                onClick={handleDemoLogin}
                className="text-xs font-bold text-orange-600 underline"
              >
                Enter Demo Mode (No Setup Required)
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (viewingItem) {
      return (
        <ItemDetail 
          item={viewingItem} 
          session={session}
          isDemoMode={isDemoMode}
          onBack={() => setViewingItem(null)} 
          onMessage={() => {
            setViewingItem(null);
            setActiveTab(Tab.MESSAGES);
          }}
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME:
        return <Marketplace onSelectItem={setViewingItem} />;
      case Tab.MESSAGES:
        return <Messages />;
      case Tab.SELL:
        return (
          <SellFlow 
            category={selectedCategory} 
            onSelectCategory={setSelectedCategory} 
            session={session}
            isDemoMode={isDemoMode}
            onCancel={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
            onSuccess={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
          />
        );
      case Tab.PROFILE:
        return <Profile session={session} onSelectItem={setViewingItem} />;
      default:
        return <Marketplace onSelectItem={setViewingItem} />;
    }
  };

  return (
    <div className="min-h-screen pb-20 bg-gray-50">
      <div className="max-w-md mx-auto relative min-h-screen bg-white shadow-xl overflow-hidden">
        {renderContent()}
        <Navigation activeTab={activeTab} onTabChange={(tab) => {
          setActiveTab(tab);
          if (tab !== Tab.SELL) setSelectedCategory(null);
          setViewingItem(null);
        }} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { supabase } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  isDemoMode: boolean;
  onBack: () => void;
  onMessage: () => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, isDemoMode, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  const isOwner = session?.user?.id === item.seller_id;

  // Parse photos if they are stored as a JSON array
  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => {
    setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  };

  const handlePrev = () => {
    setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);
  };

  const handleDelete = async () => {
    if (isDemoMode) {
      alert("In Demo Mode, you can't delete items from the database. Please sign up for a real account to manage listings!");
      return;
    }

    if (!window.confirm('Are you sure you want to delete this listing? This action cannot be undone.')) {
      return;
    }

    setIsDeleting(true);
    try {
      const { error } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id);

      if (error) throw error;

      alert('Listing deleted successfully.');
      onBack();
    } catch (err: any) {
      console.error('Delete error:', err.message || err);
      alert('Failed to delete listing: ' + (err.message || 'Server error.'));
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      {/* Top Media Section */}
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button 
          onClick={onBack}
          className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100 active:scale-90 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img 
            src={photos[currentPhotoIdx]} 
            alt={item.title} 
            className="w-full h-full object-contain mix-blend-multiply transition-all duration-300"
          />

          {photos.length > 1 && (
            <>
              <button 
                onClick={handlePrev}
                className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-r-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
                </svg>
              </button>
              <button 
                onClick={handleNext}
                className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-l-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </button>
            </>
          )}
        </div>

        {/* Pagination Dots */}
        {photos.length > 0 && (
          <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center space-y-1.5 z-20">
            <div className="flex space-x-1.5">
              {photos.map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${i === currentPhotoIdx ? 'bg-orange-500 w-4' : 'bg-gray-300'}`} 
                />
              ))}
            </div>
            <span className="text-[9px] font-black text-gray-400 tracking-widest uppercase">{currentPhotoIdx + 1}/{photos.length}</span>
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
            <div className="flex items-center space-x-1.5">
              {item.brand && (
                <span className="text-sm font-bold text-orange-600 uppercase tracking-tighter">{item.brand}</span>
              )}
              <div className="bg-emerald-100 p-0.5 rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-emerald-600" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
              </div>
            </div>
          </div>
          <div className="border-2 border-orange-100 rounded-[1.25rem] px-4 py-2 flex items-center justify-center bg-white shadow-sm">
            <span className="text-xl font-black text-orange-600">${Number(item.price).toFixed(2)}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-4">
          <div className="bg-orange-50/50 border border-orange-100/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 mb-1">Condition</p>
            <p className="text-sm font-bold text-orange-600">{item.condition}</p>
          </div>
          <div className="bg-emerald-50/50 border border-emerald-100/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400 mb-1">Category</p>
            <p className="text-sm font-bold text-emerald-600">{item.category}</p>
          </div>
        </div>

        <div className="bg-emerald-50/30 border border-emerald-100 rounded-[1.5rem] p-4 mb-8 flex items-center space-x-3">
          <div className="bg-orange-100 p-2.5 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <div>
            <p className="text-[10px] uppercase tracking-wider font-bold text-gray-400">Pickup Location</p>
            <p className="text-sm font-bold text-orange-600">{item.location}</p>
          </div>
        </div>

        {item.description && (
          <div className="mb-8">
            <p className="text-[11px] uppercase tracking-widest font-bold text-gray-400 mb-2">Description</p>
            <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{item.description}</p>
          </div>
