}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, isDemoMode, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  // Check for ownership
  const isOwner = session?.user?.id === item.seller_id;

  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => {
    setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  };

  const handlePrev = () => {
    setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);
  };

  const handleDelete = async () => {
    if (isDemoMode) {
      alert("Guest accounts can't delete items. Sign in to your real campus account!");
      return;
    }

    if (!window.confirm('Are you sure you want to remove this listing?')) {
      return;
    }

    setIsDeleting(true);
    try {
      console.log('Attempting delete for Item ID:', item.id);
      console.log('Current User ID:', session?.user?.id);
      console.log('Item Seller ID:', item.seller_id);

      // We call .select() after delete. 
      // If RLS blocks the delete, 'data' will be empty [] even if the API call "succeeds" with a 204.
      const { data, error, status } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id)
        .select();

      if (error) {
        throw error;
      }

      // If data is empty, it means no rows were actually deleted (likely RLS policy block)
      if (!data || data.length === 0) {
        console.warn('Delete called but 0 rows affected. RLS likely blocked the action.');
        alert('Could not delete. You may not have permission to remove this item, or it was already deleted.');
        onBack();
        return;
      }

      console.log('Successfully deleted row:', data);
      alert('Listing successfully removed.');
      onBack();
    } catch (err: any) {
      console.error('CRITICAL: Delete operation failed:', err);
      alert('Error deleting item: ' + (err.message || 'Please check your connection.'));
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      {/* Top Media Section */}
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button 
          onClick={onBack}
          className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100 active:scale-90 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img 
            src={photos[currentPhotoIdx]} 
            alt={item.title} 
            className="w-full h-full object-contain mix-blend-multiply transition-all duration-300"
          />

          {photos.length > 1 && (
            <>
              <button 
                onClick={handlePrev}
                className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-r-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
                </svg>
              </button>
              <button 
                onClick={handleNext}
                className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur p-2 rounded-l-xl text-gray-800 transition-all opacity-0 group-hover:opacity-100"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </button>
            </>
          )}
        </div>

        {/* Pagination Dots */}
        {photos.length > 0 && (
          <div className="absolute bottom-4 left-0 right-0 flex flex-col items-center space-y-1.5 z-20">
            <div className="flex space-x-1.5">
              {photos.map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${i === currentPhotoIdx ? 'bg-orange-500 w-4' : 'bg-gray-300'}`} 
                />
              ))}
            </div>
            <span className="text-[9px] font-black text-gray-400 tracking-widest uppercase">{currentPhotoIdx + 1}/{photos.length}</span>
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="px-6 pb-24 pt-6">
