import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  listings?: { title: string; image_url: string };
  other_user_id: string;
}

const Messages: React.FC = () => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchSession();
  }, []);

  const fetchSession = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    if (session) {
      setCurrentUserId(session.user.id);
      fetchConversations(session.user.id);
    } else {
      setLoading(false);
    }
  };

  const fetchConversations = async (userId: string) => {
    try {
      // Fetch conversations where user is buyer OR seller
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id,
          listings ( title, image_url )
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) throw error;

      if (data) {
        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err) {
      console.error('Error fetching conversations:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error(error);
    else setMessages(data || []);
  };

  // Real-time subscription for messages
  useEffect(() => {
    if (!selectedConversation) return;

    fetchMessages(selectedConversation.id);

    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages(prev => [...prev, payload.new as Message]);
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;

    const text = inputValue.trim();
    setInputValue('');

    const { error } = await supabase
      .from('messages')
      .insert({
        conversation_id: selectedConversation.id,
        sender_id: currentUserId,
        text: text
      });

    if (error) {
      console.error('Send error:', error);
      alert('Failed to send message');
    }
  };

  if (selectedConversation) {
    const otherUserAvatar = `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedConversation.other_user_id}`;

    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-2 px-6 flex flex-col items-center">
          <div className="flex items-center w-full justify-between mb-4">
            <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-4 text-gray-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
              </svg>
            </button>
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">{selectedConversation.listings?.title}</h3>
            <div className="w-10" />
          </div>

          <div className="w-full bg-[#F3F3F3] rounded-[1.75rem] py-4 px-4 flex flex-col items-center space-y-2 mb-2">
            <img src={otherUserAvatar} className="w-16 h-16 rounded-full border-2 border-white shadow-sm" alt="User" />
            <h2 className="text-sm font-bold text-gray-800 tracking-tight">Campus User</h2>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-3">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-4 py-2.5 rounded-2xl text-sm ${
                  isMe ? 'bg-[#FF8C42] text-white rounded-br-none' : 'bg-[#EDEDED] text-gray-800 rounded-bl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-10 border-t border-gray-50">
          <div className="flex items-center space-x-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Message..." 
              className="flex-1 bg-[#F3F3F3] border border-gray-200 rounded-2xl px-5 py-3 text-sm focus:outline-none"
            />
            <button onClick={handleSendMessage} className="bg-orange-500 text-white p-3 rounded-2xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-14 pb-6 px-6">
        <h1 className="text-3xl font-black text-gray-900 tracking-tight">Inbox</h1>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
        {loading ? (
          <div className="flex flex-col items-center py-20">
            <div className="w-6 h-6 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : conversations.map((conv) => (
          <div 
            key={conv.id} 
            onClick={() => setSelectedConversation(conv)}
            className="mx-4 mb-4 p-5 flex items-center space-x-4 bg-white rounded-[2rem] border-2 border-emerald-500 shadow-sm active:scale-95 transition-all cursor-pointer"
          >
            <img 
              src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${conv.other_user_id}`} 
              className="w-14 h-14 rounded-[1.25rem] bg-orange-50" 
              alt="Other User" 
            />
            <div className="flex-1">
              <h3 className="font-bold text-gray-900">{conv.listings?.title || 'Unknown Item'}</h3>
              <p className="text-xs text-gray-500 font-medium">Click to chat</p>
            </div>
            <div className="text-emerald-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </div>
        ))}

        {!loading && conversations.length === 0 && (
          <div className="flex flex-col items-center justify-center py-20 text-gray-400">
            <p className="font-bold uppercase tracking-widest text-[10px]">No active conversations</p>
          </div>
        )}
      </div>
    </div>
  );
};

