import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  listings?: { title: string; image_url: string };
  other_user_id: string;
}

const Messages: React.FC = () => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'other'>('none');
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const setupSQL = `
-- 1. Create Listings table
create table if not exists public.listings (
  id uuid default gen_random_uuid() primary key,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null default auth.uid()
);

-- 2. Create Conversations table
create table if not exists public.conversations (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  listing_id uuid references public.listings(id) on delete cascade,
  buyer_id uuid not null references auth.users(id),
  seller_id uuid not null references auth.users(id),
  unique(listing_id, buyer_id)
);

-- 3. Create Messages table
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  conversation_id uuid not null references public.conversations(id) on delete cascade,
  sender_id uuid not null references auth.users(id),
  text text not null
);

-- 4. Enable RLS and Realtime
alter table public.listings enable row level security;
alter table public.conversations enable row level security;
alter table public.messages enable row level security;

-- Policies
create policy "Anyone can view listings" on public.listings for select using (true);
create policy "Users can view their conversations" on public.conversations for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
create policy "Users can start conversations" on public.conversations for insert with check (auth.uid() = buyer_id);
create policy "Users can view messages" on public.messages for select using (exists (select 1 from public.conversations where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())));
create policy "Users can send messages" on public.messages for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    fetchSession();
  }, []);

  const fetchSession = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    if (session) {
      setCurrentUserId(session.user.id);
      fetchConversations(session.user.id);
    } else {
      setLoading(false);
    }
  };

  const fetchConversations = async (userId: string) => {
    try {
      setErrorType('none');
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id,
          listings ( title, image_url )
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else {
          setErrorType('other');
          console.error('Error fetching conversations:', error.message || error);
        }
        throw error;
      }

      if (data) {
        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err) {
      // Error handled in logic
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error(error.message);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation) return;
    fetchMessages(selectedConversation.id);
    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages(prev => [...prev, payload.new as Message]);
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');
    const { error } = await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
    if (error) alert('Failed to send: ' + error.message);
  };

  if (errorType === 'table_missing') {
    return (
      <div className="flex flex-col h-full bg-white p-6 justify-center items-center text-center space-y-6">
        <div className="w-20 h-20 bg-orange-100 rounded-[2.5rem] flex items-center justify-center text-orange-600">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-2xl font-black text-gray-900">Enable DMs</h2>
          <p className="text-xs text-gray-400 font-medium px-4">
            The conversation tables aren't set up in your database yet. Run this SQL in your Supabase dashboard:
          </p>
        </div>
        <pre className="w-full bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-40 no-scrollbar select-all text-left">
          {setupSQL}
        </pre>
        <button 
          onClick={() => { setLoading(true); fetchSession(); }}
          className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all shadow-xl shadow-orange-100 uppercase tracking-widest text-xs"
        >
          Check Connection
        </button>
      </div>
    );
  }

  if (selectedConversation) {
    const otherUserAvatar = `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedConversation.other_user_id}`;
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-2 px-6 flex flex-col items-center">
          <div className="flex items-center w-full justify-between mb-4">
            <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-4 text-gray-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
              </svg>
            </button>
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest truncate max-w-[150px]">{selectedConversation.listings?.title}</h3>
            <div className="w-10" />
          </div>
          <div className="w-full bg-[#F3F3F3] rounded-[1.75rem] py-4 px-4 flex flex-col items-center space-y-2 mb-2">
            <img src={otherUserAvatar} className="w-16 h-16 rounded-full border-2 border-white shadow-sm" alt="User" />
            <h2 className="text-sm font-bold text-gray-800 tracking-tight">Campus User</h2>
          </div>
        </div>
        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-3">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-4 py-2.5 rounded-2xl text-sm ${isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none'}`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>
        <div className="p-4 pb-10 border-t border-gray-50">
          <div className="flex items-center space-x-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Message..." 
              className="flex-1 bg-gray-50 border border-gray-200 rounded-2xl px-5 py-3 text-sm focus:outline-none"
            />
            <button onClick={handleSendMessage} className="bg-orange-500 text-white p-3 rounded-2xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-14 pb-6 px-6">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
      </div>
      <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
        {loading ? (
          <div className="flex flex-col items-center py-20"><div className="w-6 h-6 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>
        ) : conversations.map((conv) => (
          <div 
            key={conv.id} 
            onClick={() => setSelectedConversation(conv)}
            className="mx-4 mb-3 p-4 flex items-center space-x-4 bg-white rounded-3xl border border-gray-100 shadow-sm active:scale-95 transition-all cursor-pointer hover:border-orange-100"
          >
            <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${conv.other_user_id}`} className="w-14 h-14 rounded-2xl bg-orange-50 border border-orange-100" alt="Avatar" />
            <div className="flex-1">
              <h3 className="font-bold text-gray-900 text-sm">{conv.listings?.title || 'Unknown Item'}</h3>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Active Chat</p>
            </div>
            <div className="text-orange-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </div>
        ))}
        {!loading && conversations.length === 0 && (
          <div className="flex flex-col items-center justify-center py-24 text-gray-300">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <p className="font-black uppercase tracking-widest text-[10px]">Your inbox is empty</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState, useEffect } from 'react';
import { Tab, Category } from './types';
import Navigation from './components/Navigation';
import SellFlow from './components/SellFlow';
import Profile from './components/Profile';
import Marketplace from './components/Marketplace';
import Messages from './components/Messages';
import ItemDetail from './components/ItemDetail';
import Login from './components/Login';
import { supabase, isSupabaseConfigured } from './lib/supabase';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [viewingItem, setViewingItem] = useState<any>(null);
  const [isDemoMode, setIsDemoMode] = useState(!isSupabaseConfigured);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    // Check initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) setIsDemoMode(false);
      else setIsDemoMode(!isSupabaseConfigured);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleDemoLogin = () => {
    setIsDemoMode(true);
    setSession({ user: { email: 'demo@utdallas.edu', id: 'demo-user' } });
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-orange-600 font-bold animate-pulse tracking-tighter text-xl">Hucksta</p>
        </div>
      </div>
    );
  }

  if (!session) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white shadow-2xl rounded-[3rem] overflow-hidden min-h-[852px]">
          <Login onLogin={handleDemoLogin} />
          {!isSupabaseConfigured && (
            <div className="px-8 pb-8 -mt-8 text-center">
              <p className="text-[10px] text-gray-400 mb-2 italic">Backend not connected yet.</p>
              <button 
                onClick={handleDemoLogin}
                className="text-xs font-bold text-orange-600 underline"
              >
                Enter Demo Mode (No Setup Required)
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (viewingItem) {
      return (
        <ItemDetail 
          item={viewingItem} 
          session={session}
          isDemoMode={isDemoMode}
          onBack={() => setViewingItem(null)} 
          onMessage={() => {
            setViewingItem(null);
            setActiveTab(Tab.MESSAGES);
          }}
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME:
        return <Marketplace onSelectItem={setViewingItem} />;
      case Tab.MESSAGES:
        return <Messages session={session} isDemoMode={isDemoMode} />;
      case Tab.SELL:
        return (
          <SellFlow 
            category={selectedCategory} 
            onSelectCategory={setSelectedCategory} 
            session={session}
            isDemoMode={isDemoMode}
            onCancel={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
            onSuccess={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
          />
        );
      case Tab.PROFILE:
        return <Profile session={session} onSelectItem={setViewingItem} />;
      default:
        return <Marketplace onSelectItem={setViewingItem} />;
    }
  };

  return (
    <div className="min-h-screen pb-20 bg-gray-50">
      <div className="max-w-md mx-auto relative min-h-screen bg-white shadow-xl overflow-hidden">
        {renderContent()}
        <Navigation activeTab={activeTab} onTabChange={(tab) => {
          setActiveTab(tab);
          if (tab !== Tab.SELL) setSelectedCategory(null);
          setViewingItem(null);
        }} />
      </div>
    </div>
  );
};

