        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else {
          setErrorType('other');
          setErrorMsg(error.message || 'Unknown database error');
