        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err: any) {
      console.error('Conversation fetch failed:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    if (isDemoMode) {
      setMessages([
        { id: 'm1', text: 'Hey, is the hoodie still available?', sender_id: currentUserId, created_at: new Date().toISOString() },
        { id: 'm2', text: 'Yes! Can you meet at the Student Union?', sender_id: 'demo-seller', created_at: new Date().toISOString() }
      ]);
      return;
    }

    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error(error.message);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation) return;
    fetchMessages(selectedConversation.id);

    if (isDemoMode) return;

    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages(prev => [...prev, payload.new as Message]);
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [selectedConversation, isDemoMode]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');

    if (isDemoMode) {
      setMessages(prev => [...prev, { id: Date.now().toString(), text, sender_id: currentUserId, created_at: new Date().toISOString() }]);
      return;
    }

    const { error } = await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
    if (error) alert('Failed to send: ' + error.message);
  };

  if (errorType !== 'none' && !isDemoMode) {
    return (
      <div className="flex flex-col h-full bg-white p-6 justify-center items-center text-center space-y-6">
        <div className="w-20 h-20 bg-orange-100 rounded-[2.5rem] flex items-center justify-center text-orange-600">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-2xl font-black text-gray-900">
            {errorType === 'table_missing' ? 'Enable DMs' : 'Database Error'}
          </h2>
          <p className="text-xs text-gray-400 font-medium px-4">
            {errorType === 'table_missing' 
              ? "The conversation tables aren't set up yet. Run this SQL in your Supabase dashboard:"
              : `There was an error connecting: ${errorMsg}`}
          </p>
        </div>

        {errorType === 'table_missing' && (
          <div className="w-full space-y-3">
            <pre className="w-full bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-40 no-scrollbar select-all text-left border border-white/10">
              {setupSQL}
            </pre>
            <button 
              onClick={() => {
                navigator.clipboard.writeText(setupSQL);
                alert('SQL copied to clipboard!');
              }}
              className="text-[10px] font-bold text-orange-600 uppercase tracking-widest"
            >
              Copy SQL Script
            </button>
          </div>
        )}

        <button 
          onClick={() => { setLoading(true); window.location.reload(); }}
          className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all shadow-xl shadow-orange-100 uppercase tracking-widest text-xs"
        >
          Check Connection
        </button>
      </div>
    );
  }

  if (selectedConversation) {
    const otherUserAvatar = `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedConversation.other_user_id}`;
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-2 px-6 flex flex-col items-center">
          <div className="flex items-center w-full justify-between mb-4">
            <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-4 text-gray-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
              </svg>
            </button>
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest truncate max-w-[150px]">{selectedConversation.listings?.title}</h3>
            <div className="w-10" />
          </div>
          <div className="w-full bg-[#F3F3F3] rounded-[1.75rem] py-4 px-4 flex flex-col items-center space-y-2 mb-2">
            <img src={otherUserAvatar} className="w-16 h-16 rounded-full border-2 border-white shadow-sm" alt="User" />
            <h2 className="text-sm font-bold text-gray-800 tracking-tight">Campus User</h2>
          </div>
        </div>
        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-3">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-4 py-2.5 rounded-2xl text-sm ${isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none'}`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>
        <div className="p-4 pb-10 border-t border-gray-50">
          <div className="flex items-center space-x-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Message..." 
              className="flex-1 bg-gray-50 border border-gray-200 rounded-2xl px-5 py-3 text-sm focus:outline-none"
            />
            <button onClick={handleSendMessage} className="bg-orange-500 text-white p-3 rounded-2xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-14 pb-6 px-6">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
      </div>
      <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
        {loading ? (
          <div className="flex flex-col items-center py-20"><div className="w-6 h-6 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>
        ) : conversations.map((conv) => (
          <div 
            key={conv.id} 
            onClick={() => setSelectedConversation(conv)}
            className="mx-4 mb-3 p-4 flex items-center space-x-4 bg-white rounded-3xl border border-gray-100 shadow-sm active:scale-95 transition-all cursor-pointer hover:border-orange-100"
          >
            <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${conv.other_user_id}`} className="w-14 h-14 rounded-2xl bg-orange-50 border border-orange-100" alt="Avatar" />
            <div className="flex-1">
              <h3 className="font-bold text-gray-900 text-sm">{conv.listings?.title || 'Unknown Item'}</h3>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{isDemoMode ? 'Demo Chat' : 'Active Chat'}</p>
            </div>
            <div className="text-orange-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </div>
        ))}
        {!loading && conversations.length === 0 && (
          <div className="flex flex-col items-center justify-center py-24 text-gray-300">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <p className="font-black uppercase tracking-widest text-[10px]">Your inbox is empty</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- 1. Create the listings table
create table if not exists public.listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null default auth.uid()
);

-- 2. Create Conversations table (Unique room per buyer+seller+item)
create table if not exists public.conversations (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  listing_id uuid references public.listings(id) on delete cascade,
  buyer_id uuid not null references auth.users(id),
  seller_id uuid not null references auth.users(id),
  unique(listing_id, buyer_id)
);

-- 3. Create Messages table
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  conversation_id uuid not null references public.conversations(id) on delete cascade,
  sender_id uuid not null references auth.users(id),
  text text not null
);

-- 4. Enable RLS
alter table public.listings enable row level security;
alter table public.conversations enable row level security;
alter table public.messages enable row level security;

-- 5. Enable Realtime (Ignore errors if already enabled)
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication WHERE pubname = 'supabase_realtime') THEN
    CREATE PUBLICATION supabase_realtime;
  END IF;
END $$;

-- Add tables to publication individually to avoid "already exists" errors
DO $$
BEGIN
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE listings;
  EXCEPTION WHEN others THEN END;
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE conversations;
  EXCEPTION WHEN others THEN END;
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE messages;
  EXCEPTION WHEN others THEN END;
END $$;

-- 6. Policies (Listings)
drop policy if exists "Anyone can view listings" on public.listings;
drop policy if exists "Users can add items" on public.listings;
drop policy if exists "Users can delete their items" on public.listings;
create policy "Anyone can view listings" on public.listings for select using (true);
create policy "Users can add items" on public.listings for insert with check (auth.uid() = seller_id);
create policy "Users can delete their items" on public.listings for delete using (auth.uid() = seller_id);

-- 7. Policies (Conversations)
drop policy if exists "Users can view their conversations" on public.conversations;
drop policy if exists "Users can start conversations" on public.conversations;
create policy "Users can view their conversations" on public.conversations 
  for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
create policy "Users can start conversations" on public.conversations 
  for insert with check (auth.uid() = buyer_id);

-- 8. Policies (Messages)
drop policy if exists "Users can view messages in their conversations" on public.messages;
drop policy if exists "Users can send messages" on public.messages;
create policy "Users can view messages in their conversations" on public.messages 
  for select using (
    exists (
      select 1 from public.conversations 
      where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())
    )
  );
create policy "Users can send messages" on public.messages 
  for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-realtime')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') setErrorType('table_missing');
        else setErrorType('other');
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = listings.filter(item => item.category === activeCategory);

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
