import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  listings?: { title: string; image_url: string };
  other_user_id: string;
}

interface MessagesProps {
  session: any;
  isDemoMode: boolean;
}

const Messages: React.FC<MessagesProps> = ({ session, isDemoMode }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentUserId = session?.user?.id;

  const setupSQL = `
-- 1. Create Conversations table
-- (You MUST create this for the DM feature to work)
create table if not exists public.conversations (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  listing_id uuid references public.listings(id) on delete cascade,
  buyer_id uuid not null references auth.users(id),
  seller_id uuid not null references auth.users(id),
  unique(listing_id, buyer_id)
);

-- 2. Create Messages table (if not already created)
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  conversation_id uuid not null references public.conversations(id) on delete cascade,
  sender_id uuid not null references auth.users(id),
  text text not null
);

-- 3. Enable RLS and Realtime
alter table public.conversations enable row level security;
alter table public.messages enable row level security;

-- Policies
create policy "Users can view their own conversations" on public.conversations for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
create policy "Users can start conversations" on public.conversations for insert with check (auth.uid() = buyer_id);
create policy "Users can view messages in their chats" on public.messages for select using (exists (select 1 from public.conversations where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())));
create policy "Users can send messages" on public.messages for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    if (isDemoMode) {
      setConversations([
        {
          id: 'demo-1',
          listing_id: 'demo-item',
          buyer_id: currentUserId,
          seller_id: 'demo-seller',
          other_user_id: 'demo-seller',
          listings: { title: 'Vintage UTD Hoodie', image_url: '' }
        },
        {
          id: 'demo-2',
          listing_id: 'demo-item-2',
          buyer_id: currentUserId,
          seller_id: 'demo-seller-2',
          other_user_id: 'demo-seller-2',
          listings: { title: 'IKEA Desk', image_url: '' }
        }
      ]);
      setLoading(false);
    } else if (currentUserId) {
      fetchConversations(currentUserId);
    }
  }, [currentUserId, isDemoMode]);

  const fetchConversations = async (userId: string) => {
    try {
      setErrorType('none');
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id,
          listings ( title, image_url )
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) {
        if (error.code === '42P01') {
          setErrorType('table_missing');
        } else {
          setErrorType('other');
          setErrorMsg(error.message);
        }
        throw error;
      }

      if (data) {
        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err: any) {
      console.error('Conversation fetch failed:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    if (isDemoMode) {
      setMessages([
        { id: 'm1', text: 'Hey, is the hoodie still available?', sender_id: currentUserId, created_at: new Date().toISOString() },
        { id: 'm2', text: 'Yes! Can you meet at the Student Union later today?', sender_id: 'demo-seller', created_at: new Date().toISOString() }
      ]);
      return;
    }

    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error(error.message);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation) return;
    fetchMessages(selectedConversation.id);

    if (isDemoMode) return;

    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages(prev => [...prev, payload.new as Message]);
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [selectedConversation, isDemoMode]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');

    if (isDemoMode) {
      setMessages(prev => [...prev, { id: Date.now().toString(), text, sender_id: currentUserId, created_at: new Date().toISOString() }]);
      return;
    }

    const { error } = await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
    if (error) alert('Failed to send: ' + error.message);
  };

  if (errorType !== 'none' && !isDemoMode) {
    return (
      <div className="flex flex-col h-full bg-white p-6 justify-center items-center text-center space-y-6">
        <div className="w-20 h-20 bg-orange-100 rounded-[2.5rem] flex items-center justify-center text-orange-600">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-2xl font-black text-gray-900">Finish Setting Up DMs</h2>
          <p className="text-xs text-gray-400 font-medium px-4 leading-relaxed">
            The <b>conversations</b> table is missing. Run this SQL in your Supabase dashboard to link your messages:
          </p>
        </div>

        <div className="w-full space-y-3">
          <pre className="w-full bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-40 no-scrollbar select-all text-left border border-white/10 shadow-inner">
            {setupSQL}
          </pre>
          <button 
            onClick={() => {
              navigator.clipboard.writeText(setupSQL);
              alert('SQL copied! Paste it into Supabase SQL Editor.');
            }}
            className="text-[10px] font-bold text-orange-600 uppercase tracking-widest bg-orange-50 px-4 py-2 rounded-full"
          >
            Copy SQL Script
          </button>
        </div>

        <button 
          onClick={() => { setLoading(true); window.location.reload(); }}
          className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all shadow-xl shadow-orange-100 uppercase tracking-widest text-xs"
        >
          Check Connection
        </button>
      </div>
    );
  }

  if (selectedConversation) {
    const otherUserAvatar = `https://api.dicebear.com/7.x/avataaars/svg?seed=${selectedConversation.other_user_id}`;
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        {/* Chat Header */}
        <div className="pt-12 pb-2 px-6 flex flex-col items-center bg-white border-b border-gray-50">
          <div className="flex items-center w-full justify-between mb-4">
            <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-4 text-gray-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
              </svg>
            </button>
            <div className="flex flex-col items-center text-center">
              <h3 className="text-[10px] font-black text-gray-300 uppercase tracking-[0.2em] truncate max-w-[150px] mb-0.5">
                Regarding item
              </h3>
              <h4 className="text-xs font-bold text-gray-800 truncate max-w-[180px]">
                {selectedConversation.listings?.title}
              </h4>
            </div>
            <div className="w-10" />
          </div>

          <div className="w-full py-4 px-4 flex flex-col items-center space-y-1">
            <img src={otherUserAvatar} className="w-14 h-14 rounded-3xl border-2 border-white shadow-md bg-orange-50" alt="User" />
            <h2 className="text-sm font-bold text-gray-900">Campus Seller</h2>
            <div className="flex items-center space-x-1">
              <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
              <span className="text-[10px] text-emerald-600 font-bold uppercase tracking-widest">Active now</span>
            </div>
          </div>
        </div>

        {/* Messages List */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-4 bg-gray-50/30">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.75rem] text-sm shadow-sm transition-all duration-200 ${
                  isMe 
                  ? 'bg-orange-500 text-white rounded-br-none shadow-orange-100' 
                  : 'bg-white text-gray-800 rounded-bl-none border border-gray-100'
                }`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        {/* Input Area */}
        <div className="p-4 pb-10 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-3">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Type a message..." 
              className="flex-1 bg-gray-50 border border-gray-100 rounded-2xl px-6 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-orange-100 focus:bg-white transition-all"
            />
            <button 
              onClick={handleSendMessage} 
              className="bg-orange-500 text-white p-4 rounded-2xl shadow-lg shadow-orange-100 active:scale-90 transition-transform"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-14 pb-6 px-8 bg-white border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Direct Messages</p>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24 px-4 pt-4 bg-gray-50/30">
        {loading ? (
          <div className="flex flex-col items-center py-20">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mt-4">Syncing chats...</p>
          </div>
        ) : conversations.map((conv) => (
          <div 
            key={conv.id} 
            onClick={() => setSelectedConversation(conv)}
            className="mb-3 p-5 flex items-center space-x-4 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:border-orange-200"
          >
            <div className="relative">
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${conv.other_user_id}`} className="w-16 h-16 rounded-[1.5rem] bg-orange-50 border border-orange-100" alt="Avatar" />
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-orange-500 rounded-full border-2 border-white"></div>
            </div>
            <div className="flex-1">
              <h3 className="font-bold text-gray-900 text-sm leading-tight mb-0.5">{conv.listings?.title || 'Campus Item'}</h3>
              <p className="text-[10px] text-orange-500 font-black uppercase tracking-widest">Active Discussion</p>
            </div>
            <div className="text-gray-300">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </div>
        ))}

        {!loading && conversations.length === 0 && (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 px-10 text-center">
            <div className="bg-white p-8 rounded-[3rem] shadow-sm mb-6 border border-gray-50">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 opacity-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
              </svg>
            </div>
            <h3 className="text-gray-800 font-bold mb-1">No chats yet</h3>
            <p className="text-xs font-medium text-gray-400">Items you message sellers about will show up here.</p>
          </div>
        )}
      </div>
    </div>
  );
};

