import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'auth_error' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- 1. Create the listings table
create table if not exists public.listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null default auth.uid()
);

-- 2. Create Conversations table
create table if not exists public.conversations (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  listing_id uuid references public.listings(id) on delete cascade,
  buyer_id uuid not null references auth.users(id),
  seller_id uuid not null references auth.users(id),
  unique(listing_id, buyer_id)
);

-- 3. Create Messages table
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  conversation_id uuid not null references public.conversations(id) on delete cascade,
  sender_id uuid not null references auth.users(id),
  text text not null
);

-- 4. Enable RLS
alter table public.listings enable row level security;
alter table public.conversations enable row level security;
alter table public.messages enable row level security;

-- 5. Enable Realtime
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication WHERE pubname = 'supabase_realtime') THEN
    CREATE PUBLICATION supabase_realtime;
  END IF;
END $$;

DO $$
BEGIN
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE listings;
  EXCEPTION WHEN others THEN END;
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE conversations;
  EXCEPTION WHEN others THEN END;
  BEGIN
    ALTER PUBLICATION supabase_realtime ADD TABLE messages;
  EXCEPTION WHEN others THEN END;
END $$;

-- 6. Policies
drop policy if exists "Anyone can view listings" on public.listings;
drop policy if exists "Users can add items" on public.listings;
create policy "Anyone can view listings" on public.listings for select using (true);
create policy "Users can add items" on public.listings for insert with check (auth.uid() = seller_id);
create policy "Users can delete their items" on public.listings for delete using (auth.uid() = seller_id);

drop policy if exists "Users can view their conversations" on public.conversations;
create policy "Users can view their conversations" on public.conversations 
  for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
create policy "Users can start conversations" on public.conversations 
  for insert with check (auth.uid() = buyer_id);

drop policy if exists "Users can view messages in their conversations" on public.messages;
create policy "Users can view messages in their conversations" on public.messages 
  for select using (
    exists (
      select 1 from public.conversations 
      where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())
    )
  );
create policy "Users can send messages" on public.messages 
  for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-realtime')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') setErrorType('table_missing');
        else setErrorType('other');
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = listings.filter(item => item.category === activeCategory);

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-br from-emerald-400 via-orange-500 to-[#F27F44] overflow-y-auto no-scrollbar">
      <div className="pt-14 pb-4 px-4 flex flex-col items-center z-10">
        <h1 className="text-5xl font-black text-white tracking-tight text-shadow-sm">Hucksta</h1>
        <div className="mt-2 flex items-center space-x-1 bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
          <div className={`w-1.5 h-1.5 rounded-full ${errorType === 'none' ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></div>
          <span className="text-[10px] font-bold text-white uppercase tracking-widest">
            {errorType === 'none' ? 'Campus Live' : 'Fix Needed'}
          </span>
        </div>
      </div>

      {errorType === 'table_missing' ? (
        <div className="flex-1 p-6 flex flex-col">
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl flex flex-col items-center text-center space-y-4">
            <div className="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center text-orange-600 mb-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
            </div>
            <h2 className="text-xl font-black text-gray-800">Setup Database</h2>
            <p className="text-xs text-gray-500 font-medium leading-relaxed">
              To enable Realtime DMs and Marketplace listings, copy this script to your Supabase SQL Editor:
            </p>

            <div className="w-full text-left">
              <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar border border-white/10 shadow-inner select-all">
                {setupSQL}
              </pre>
            </div>

            <button 
              onClick={() => {
                setLoading(true);
                fetchListings();
              }}
              className="w-full bg-orange-600 text-white font-bold py-4 rounded-2xl active:scale-95 transition-all shadow-xl uppercase tracking-widest text-xs"
            >
              Verify Fix
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="pb-6 px-4">
            <div className="flex items-center pt-6 mb-6">
              <div className="relative flex-1">
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-orange-400">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                </div>
                <input 
                  type="text" 
                  placeholder="Search campus items..." 
                  className="w-full h-12 pl-12 pr-4 bg-white rounded-2xl text-sm font-medium focus:outline-none shadow-xl shadow-black/10 placeholder-gray-400"
                />
              </div>
            </div>

            <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
              {categories.map((cat) => (
                <button 
                  key={cat.name} 
                  onClick={() => setActiveCategory(cat.name)}
                  className={`flex items-center space-x-2 px-6 py-3 rounded-full whitespace-nowrap transition-all duration-200 shadow-sm border ${
                    activeCategory === cat.name 
                    ? 'bg-white text-orange-600 border-white' 
                    : 'bg-white/20 text-white border-white/30 backdrop-blur-md hover:bg-white/30'
                  }`}
                >
                  <span className="text-lg">{cat.icon}</span>
                  <span className="text-sm font-bold uppercase tracking-wide">{cat.name}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="flex-1 p-3 pb-24">
            {loading ? (
              <div className="flex flex-col items-center justify-center py-20">
                <div className="w-8 h-8 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
              </div>
            ) : displayedItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                <h3 className="text-white text-xl font-bold mb-2">No items listed</h3>
                <p className="text-white/60 text-xs font-medium tracking-wider">Be the first to list something!</p>
              </div>
            ) : (
              <div className="grid grid-cols-2 gap-3">
                {displayedItems.map((item: any) => (
                  <div 
                    key={item.id} 
                    onClick={() => onSelectItem?.(item)}
                    className="bg-white rounded-[2rem] p-1.5 shadow-xl flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer"
                  >
                    <div className="relative aspect-[4/5] rounded-[1.75rem] overflow-hidden mb-2">
                      <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                      <div className={`absolute top-2 left-2 px-2.5 py-1 rounded-full text-[10px] font-bold text-white shadow-md bg-emerald-600`}>
                        {item.condition}
                      </div>
                    </div>

                    <div className="px-2 pb-2">
                      <h3 className="font-bold text-gray-800 text-xs leading-tight mb-1 line-clamp-2 h-8">{item.title}</h3>
                      <p className="text-[10px] text-gray-400 font-bold mb-1 truncate uppercase tracking-tighter">{item.brand || item.category}</p>
                      <div className="flex items-center text-emerald-600 mb-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 mr-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                        </svg>
                        <span className="text-[9px] font-bold line-clamp-1">{item.location}</span>
                      </div>
                      <p className="text-orange-600 font-black text-lg">${Number(item.price).toFixed(2)}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

