import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  listings?: { title: string; image_url: string };
  other_user_id: string;
}

interface MessagesProps {
  session: any;
  isDemoMode: boolean;
}

const Messages: React.FC<MessagesProps> = ({ session, isDemoMode }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'setup_needed' | 'other'>('none');
  const [errorMsg, setErrorMsg] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentUserId = session?.user?.id;

  // The "Bulletproof" script to fix the backend
  const setupSQL = `
-- 1. Ensure the conversations table exists (The 'Room' for chats)
create table if not exists public.conversations (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  listing_id uuid references public.listings(id) on delete cascade,
  buyer_id uuid not null references auth.users(id),
  seller_id uuid not null references auth.users(id),
  unique(listing_id, buyer_id)
);

-- 2. Ensure the messages table exists and links to conversations
create table if not exists public.messages (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  conversation_id uuid not null references public.conversations(id) on delete cascade,
  sender_id uuid not null references auth.users(id),
  text text not null
);

-- 3. Enable Realtime for instant messaging
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication WHERE pubname = 'supabase_realtime') THEN
    CREATE PUBLICATION supabase_realtime;
  END IF;
END $$;

ALTER PUBLICATION supabase_realtime ADD TABLE conversations;
ALTER PUBLICATION supabase_realtime ADD TABLE messages;

-- 4. Set up Security (RLS)
alter table public.conversations enable row level security;
alter table public.messages enable row level security;

-- Policies for Conversations
drop policy if exists "View own chats" on public.conversations;
create policy "View own chats" on public.conversations 
  for select using (auth.uid() = buyer_id or auth.uid() = seller_id);

drop policy if exists "Start a chat" on public.conversations;
create policy "Start a chat" on public.conversations 
  for insert with check (auth.uid() = buyer_id);

-- Policies for Messages
drop policy if exists "View messages in my chats" on public.messages;
create policy "View messages in my chats" on public.messages 
  for select using (
    exists (
      select 1 from public.conversations 
      where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())
    )
  );

drop policy if exists "Send messages" on public.messages;
create policy "Send messages" on public.messages 
  for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    if (isDemoMode) {
      setConversations([
        {
          id: 'demo-1',
          listing_id: 'demo-item',
          buyer_id: currentUserId,
          seller_id: 'demo-seller',
          other_user_id: 'demo-seller',
          listings: { title: 'Vintage UTD Hoodie', image_url: '' }
        }
      ]);
      setLoading(false);
    } else if (currentUserId) {
      fetchConversations(userIdWithCheck(currentUserId));
    }
  }, [currentUserId, isDemoMode]);

  const userIdWithCheck = (id: string) => id;

  const fetchConversations = async (userId: string) => {
    try {
      setErrorType('none');
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id,
          listings ( title, image_url )
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) {
        if (error.code === '42P01') {
          setErrorType('setup_needed');
        } else {
          setErrorType('other');
          setErrorMsg(error.message || 'Check your Supabase logs');
        }
        throw error;
      }

      if (data) {
        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    if (isDemoMode) {
      setMessages([
        { id: 'm1', text: 'Hey, is the hoodie still available?', sender_id: currentUserId, created_at: new Date().toISOString() },
        { id: 'm2', text: 'Yes! Can you meet at the Student Union?', sender_id: 'demo-seller', created_at: new Date().toISOString() }
      ]);
      return;
    }

    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error(error.message);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation || isDemoMode) return;

    fetchMessages(selectedConversation.id);

    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages(prev => [...prev, payload.new as Message]);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');

    if (isDemoMode) {
      setMessages(prev => [...prev, { id: Date.now().toString(), text, sender_id: currentUserId, created_at: new Date().toISOString() }]);
      return;
    }

    const { error } = await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
    if (error) alert('Message failed: ' + error.message);
  };

  if (errorType === 'setup_needed' && !isDemoMode) {
    return (
      <div className="flex flex-col h-full bg-white p-8 justify-center items-center text-center space-y-6">
        <div className="w-24 h-24 bg-orange-50 rounded-[2.5rem] flex items-center justify-center text-orange-600 mb-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
          </svg>
        </div>
        <div>
          <h2 className="text-2xl font-black text-gray-900 mb-2">Finish Setup</h2>
          <p className="text-sm text-gray-400 font-medium leading-relaxed">
            The <b>conversations</b> table is missing! To enable DMs, run this script in your Supabase SQL Editor:
          </p>
        </div>

        <div className="w-full">
          <pre className="w-full bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[9px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar border border-white/10 text-left select-all">
            {setupSQL}
          </pre>
          <button 
            onClick={() => {
              navigator.clipboard.writeText(setupSQL);
              alert('SQL Copied! Go to Supabase > SQL Editor > New Query and paste it there.');
            }}
            className="mt-4 text-xs font-black text-orange-600 uppercase tracking-widest bg-orange-50 px-6 py-3 rounded-full active:scale-95 transition-all"
          >
            Copy SQL Script
          </button>
        </div>

        <button 
          onClick={() => { setLoading(true); fetchConversations(currentUserId); }}
          className="w-full bg-orange-600 text-white font-bold py-5 rounded-[2rem] active:scale-95 transition-all shadow-xl shadow-orange-100 uppercase tracking-widest text-sm"
        >
          Check Backend Now
        </button>
      </div>
    );
  }

  if (selectedConversation) {
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-4 px-6 flex items-center border-b border-gray-50">
          <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-2 text-gray-400 hover:text-orange-500 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="flex-1 text-center">
            <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-0.5">Regarding Item</p>
            <h3 className="text-sm font-bold text-gray-800 truncate">{selectedConversation.listings?.title}</h3>
          </div>
          <div className="w-8" />
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-4 bg-gray-50/30">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.5rem] text-sm shadow-sm ${
                  isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-white text-gray-800 rounded-bl-none border border-gray-100'
                }`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-12 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-2 bg-gray-50 rounded-2xl p-2 pr-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Message..." 
              className="flex-1 bg-transparent border-none px-4 py-3 text-sm focus:outline-none"
            />
            <button 
              onClick={handleSendMessage} 
              className="bg-orange-500 text-white p-3 rounded-xl shadow-lg shadow-orange-100 active:scale-90 transition-transform"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-16 pb-6 px-8 border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
        <div className="flex items-center space-x-2 mt-2">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Campus Live</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24 p-4 space-y-3 bg-gray-50/30">
        {loading ? (
          <div className="flex flex-col items-center py-20"><div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>
        ) : conversations.map((conv) => (
          <div 
            key={conv.id} 
            onClick={() => setSelectedConversation(conv)}
            className="p-5 flex items-center space-x-4 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-95 transition-all cursor-pointer hover:border-orange-100"
          >
            <div className="relative">
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${conv.other_user_id}`} className="w-14 h-14 rounded-[1.25rem] bg-orange-50 border border-orange-100" alt="User" />
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-orange-500 rounded-full border-2 border-white shadow-sm"></div>
            </div>
            <div className="flex-1">
              <h3 className="font-bold text-gray-900 text-sm mb-0.5">{conv.listings?.title || 'Campus Item'}</h3>
              <p className="text-[10px] text-orange-600 font-black uppercase tracking-widest">{isDemoMode ? 'Demo Mode' : 'Direct Message'}</p>
            </div>
            <div className="text-gray-300">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
              </svg>
            </div>
          </div>
        ))}
        {!loading && conversations.length === 0 && (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 text-center px-12">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 mb-6 opacity-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <h3 className="text-gray-900 font-bold mb-1 uppercase tracking-tighter text-lg">Empty Inbox</h3>
            <p className="text-xs font-medium text-gray-400">Message a seller to start your first campus conversation!</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState, useMemo } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  isDemoMode: boolean;
  onBack: () => void;
  onMessage: () => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, isDemoMode, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isStartingChat, setIsStartingChat] = useState(false);

  const isOwner = session?.user?.id === item.seller_id;

  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  const handlePrev = () => setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);

  const handleMessageSeller = async () => {
    if (isDemoMode) {
      alert("Guest mode doesn't support live chatting. Please sign up!");
      return;
    }

    setIsStartingChat(true);
    try {
      // 1. Check if conversation already exists
      const { data: existing, error: checkError } = await supabase
        .from('conversations')
        .select('id')
        .eq('listing_id', item.id)
        .eq('buyer_id', session.user.id)
        .single();

      if (checkError && checkError.code !== 'PGRST116') {
        if (checkError.code === '42P01') {
          alert('DM system not fully set up. Go to the "Inbox" tab to get the setup script!');
          return;
        }
        throw checkError;
      }

      if (!existing) {
        // 2. Create new conversation if none exists
        const { error: insertError } = await supabase
          .from('conversations')
          .insert({
            listing_id: item.id,
            buyer_id: session.user.id,
            seller_id: item.seller_id
          });

        if (insertError) throw insertError;
      }

      // 3. Navigate to message tab
      onMessage();
    } catch (err: any) {
      console.error('Error starting chat:', err);
      alert('Error: ' + (err.message || 'Check your database connection.'));
    } finally {
      setIsStartingChat(false);
    }
  };

  const handleDelete = async () => {
    if (isDemoMode) {
      alert("Guest accounts can't delete items.");
      return;
    }
    if (!window.confirm('Are you sure you want to remove this listing?')) return;

    setIsDeleting(true);
    try {
      const { data, error } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id)
        .select();

      if (error) throw error;
      if (!data || data.length === 0) {
        alert('Permission denied or item already removed.');
        onBack();
        return;
      }
      alert('Listing successfully removed.');
      onBack();
    } catch (err: any) {
      alert('Error deleting item: ' + err.message);
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button onClick={onBack} className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img src={photos[currentPhotoIdx]} alt={item.title} className="w-full h-full object-contain mix-blend-multiply" />
          {photos.length > 1 && (
            <>
              <button onClick={handlePrev} className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-r-xl opacity-0 group-hover:opacity-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
              </button>
              <button onClick={handleNext} className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-l-xl opacity-0 group-hover:opacity-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
              </button>
            </>
          )}
        </div>
      </div>

      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
            <span className="text-sm font-bold text-orange-600 uppercase tracking-tighter">{item.brand}</span>
          </div>
          <div className="border-2 border-orange-100 rounded-[1.25rem] px-4 py-2 bg-white shadow-sm">
            <span className="text-xl font-black text-orange-600">${Number(item.price).toFixed(2)}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-8">
          <div className="bg-orange-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Condition</p>
            <p className="text-sm font-bold text-orange-600">{item.condition}</p>
          </div>
          <div className="bg-emerald-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Category</p>
            <p className="text-sm font-bold text-emerald-600">{item.category}</p>
          </div>
        </div>

        <div className="bg-emerald-50/30 border border-emerald-100 rounded-[1.5rem] p-4 mb-8 flex items-center space-x-3">
          <div className="bg-orange-100 p-2.5 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            </svg>
          </div>
          <div><p className="text-[10px] uppercase font-bold text-gray-400">Pickup</p><p className="text-sm font-bold text-orange-600">{item.location}</p></div>
        </div>

        <div className="bg-gray-50/50 border border-gray-100 rounded-[2rem] p-5 space-y-5">
          <div className="flex items-center space-x-4">
            <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${item.seller_id}`} className="w-14 h-14 rounded-2xl bg-orange-100" />
            <div><h4 className="font-bold text-gray-900">Campus Seller</h4><p className="text-xs text-gray-400">Verified Student</p></div>
          </div>

          {isOwner ? (
            <button onClick={handleDelete} disabled={isDeleting} className="w-full bg-red-50 py-4 rounded-2xl flex items-center justify-center space-x-2 text-red-600 font-bold active:scale-95 transition-all">
              <span className="text-sm">{isDeleting ? 'Removing...' : 'Delete Listing'}</span>
            </button>
          ) : (
            <button onClick={handleMessageSeller} disabled={isStartingChat} className="w-full bg-orange-600 shadow-xl shadow-orange-100 py-4 rounded-2xl flex items-center justify-center space-x-2 text-white font-bold active:scale-95 transition-all">
              <span className="text-sm">{isStartingChat ? 'Connecting...' : 'Message Seller'}</span>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default ItemDetail;

import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  listings?: { title: string; image_url: string };
  other_user_id: string;
}

interface MessagesProps {
  session: any;
  isDemoMode: boolean;
}

const Messages: React.FC<MessagesProps> = ({ session, isDemoMode }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing'>('none');
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentUserId = session?.user?.id;

  useEffect(() => {
    if (currentUserId && !isDemoMode) {
      fetchConversations(currentUserId);
    } else {
      setLoading(false);
    }
  }, [currentUserId, isDemoMode]);

  const fetchConversations = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id,
          listings ( title, image_url )
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`);

      if (error) {
        if (error.code === '42P01') setErrorType('table_missing');
        throw error;
      }

      if (data) {
        const formatted = data.map((conv: any) => ({
          ...conv,
          other_user_id: conv.buyer_id === userId ? conv.seller_id : conv.buyer_id
        }));
        setConversations(formatted);
      }
    } catch (err) {
      console.error('Error fetching conversations:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (convId: string) => {
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });

    if (error) console.error('Error fetching messages:', error);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation || isDemoMode) return;

    fetchMessages(selectedConversation.id);

    // Subscribe to new messages
    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages((prev) => [...prev, payload.new as Message]);
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;

    const text = inputValue.trim();
    setInputValue('');

    const { error } = await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });

    if (error) {
      alert('Failed to send message: ' + error.message);
    }
  };

  if (errorType === 'table_missing') {
    return (
      <div className="flex flex-col h-full bg-white p-8 justify-center items-center text-center space-y-4">
        <div className="bg-orange-50 p-6 rounded-[2rem] text-orange-600">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
          </svg>
        </div>
        <h2 className="text-xl font-black text-gray-900">Setup Required</h2>
        <p className="text-xs text-gray-400 font-medium">You need to create the 'conversations' and 'messages' tables in Supabase to use DMs.</p>
        <button 
          onClick={() => window.location.reload()}
          className="bg-orange-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg shadow-orange-100"
        >
          Check Again
        </button>
      </div>
    );
  }

  if (selectedConversation) {
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-4 px-6 flex items-center border-b border-gray-50">
          <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-2 text-gray-400">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="flex-1 text-center">
            <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-0.5">Regarding Item</p>
            <h3 className="text-sm font-bold text-gray-800 truncate px-4">{selectedConversation.listings?.title}</h3>
          </div>
          <div className="w-8" />
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-4">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.5rem] text-sm shadow-sm ${
                  isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-12 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Type a message..." 
              className="flex-1 bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-orange-100 transition-all"
            />
            <button 
              onClick={handleSendMessage} 
              className="bg-orange-500 text-white p-3.5 rounded-2xl shadow-lg shadow-orange-100 active:scale-90 transition-transform"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-16 pb-6 px-8 border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
        <div className="flex items-center space-x-2 mt-1">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Campus Live</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24 p-4 space-y-3 bg-gray-50/30">
        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : conversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 text-center px-8">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 mb-6 opacity-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <h3 className="text-gray-900 font-bold mb-1 uppercase tracking-tighter text-lg">No Messages Yet</h3>
            <p className="text-xs font-medium text-gray-400">Items you message sellers about will appear here.</p>
          </div>
        ) : (
          conversations.map((chat) => (
            <div 
              key={chat.id} 
              onClick={() => setSelectedConversation(chat)}
              className="p-5 flex items-center space-x-4 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:border-orange-100"
            >
              <img 
                src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${chat.other_user_id}`} 
                className="w-14 h-14 rounded-[1.25rem] bg-orange-50 border border-orange-100" 
                alt="Avatar" 
              />
              <div className="flex-1">
                <h3 className="font-bold text-gray-900 text-sm mb-0.5">{chat.listings?.title || 'Campus Item'}</h3>
                <p className="text-[10px] text-orange-600 font-black uppercase tracking-widest">Active Discussion</p>
              </div>
              <div className="text-gray-300">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState, useMemo } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  isDemoMode: boolean;
  onBack: () => void;
  onMessage: () => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, isDemoMode, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isMessaging, setIsMessaging] = useState(false);

  const isOwner = session?.user?.id === item.seller_id;

  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  const handlePrev = () => setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);

  const handleMessageSeller = async () => {
    if (isDemoMode) {
      alert("Direct Messaging requires a real account. Please sign up!");
      return;
    }

    setIsMessaging(true);
    try {
      // 1. Try to find existing conversation
      const { data: existing, error: findError } = await supabase
        .from('conversations')
        .select('id')
        .eq('listing_id', item.id)
        .eq('buyer_id', session.user.id)
        .single();

      if (findError && findError.code !== 'PGRST116') {
        if (findError.code === '42P01') {
          alert('DM feature is not set up in the database. Run the SQL script from the Inbox tab.');
          return;
        }
        throw findError;
      }

      if (existing) {
        onMessage();
        return;
      }

      // 2. Create new conversation
      const { error: createError } = await supabase
        .from('conversations')
        .insert({
          listing_id: item.id,
          buyer_id: session.user.id,
          seller_id: item.seller_id
        });

      if (createError) throw createError;
      onMessage();
    } catch (err: any) {
      console.error('Error starting chat:', err);
      alert('Could not start chat: ' + (err.message || 'Unknown error'));
    } finally {
      setIsMessaging(false);
    }
  };

  const handleDelete = async () => {
    if (isDemoMode) {
      alert("Guest accounts can't delete items.");
      return;
    }
    if (!window.confirm('Are you sure you want to remove this listing?')) return;

    setIsDeleting(true);
    try {
      const { data, error } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id)
        .select();

      if (error) throw error;
      if (!data || data.length === 0) {
        alert('Permission denied or item already removed.');
        onBack();
        return;
      }
      alert('Listing successfully removed.');
      onBack();
    } catch (err: any) {
      alert('Error deleting item: ' + err.message);
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button onClick={onBack} className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img src={photos[currentPhotoIdx]} alt={item.title} className="w-full h-full object-contain mix-blend-multiply" />
          {photos.length > 1 && (
            <>
              <button onClick={handlePrev} className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-r-xl opacity-0 group-hover:opacity-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
              </button>
              <button onClick={handleNext} className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-l-xl opacity-0 group-hover:opacity-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
              </button>
            </>
          )}
        </div>
      </div>

      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
            <span className="text-sm font-bold text-orange-600 uppercase tracking-tighter">{item.brand}</span>
          </div>
          <div className="border-2 border-orange-100 rounded-[1.25rem] px-4 py-2 bg-white shadow-sm">
            <span className="text-xl font-black text-orange-600">${Number(item.price).toFixed(2)}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-8">
          <div className="bg-orange-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Condition</p>
            <p className="text-sm font-bold text-orange-600">{item.condition}</p>
          </div>
          <div className="bg-emerald-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Category</p>
            <p className="text-sm font-bold text-emerald-600">{item.category}</p>
          </div>
        </div>

        <div className="bg-emerald-50/30 border border-emerald-100 rounded-[1.5rem] p-4 mb-8 flex items-center space-x-3">
          <div className="bg-orange-100 p-2.5 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            </svg>
          </div>
          <div><p className="text-[10px] uppercase font-bold text-gray-400">Pickup</p><p className="text-sm font-bold text-orange-600">{item.location}</p></div>
        </div>

        <div className="bg-gray-50/50 border border-gray-100 rounded-[2rem] p-5 space-y-5">
          <div className="flex items-center space-x-4">
            <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${item.seller_id}`} className="w-14 h-14 rounded-2xl bg-orange-100" />
            <div><h4 className="font-bold text-gray-900">Campus Seller</h4><p className="text-xs text-gray-400">Verified Student</p></div>
          </div>

          {isOwner ? (
            <button onClick={handleDelete} disabled={isDeleting} className="w-full bg-red-50 py-4 rounded-2xl flex items-center justify-center space-x-2 text-red-600 font-bold active:scale-95 transition-all">
              <span className="text-sm">{isDeleting ? 'Removing...' : 'Delete Listing'}</span>
            </button>
          ) : (
            <button 
              onClick={handleMessageSeller} 
              disabled={isMessaging}
              className="w-full bg-orange-600 shadow-xl shadow-orange-100 py-4 rounded-2xl flex items-center justify-center space-x-2 text-white font-bold active:scale-95 transition-all"
            >
              <span className="text-sm">{isMessaging ? 'Connecting...' : 'Message Seller'}</span>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default ItemDetail;

