import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';

interface ClothingListingFormProps {
  onBack: () => void;
  onSuccess?: () => void;
  session: any;
  isDemoMode: boolean;
}

const locations = [
  'UTD Visitor Center', 'Founders North Plaza', 'Founders South Plaza', 'Comets Landing',
  'Davidson-Gundy Alumni Center', 'Administration Building', 'Bioengineering and Sciences Building',
  'Callier Center Richardson', 'Activity Center', 'Dining Hall West', 'Sirius Hall',
  'Berkner Hall', 'Cecil H. Green Hall', 'Engineering and Computer Science Buildings',
  'Naveen Jindal School of Management', 'McDermott Library', 'Student Union'
];

const ClothingListingForm: React.FC<ClothingListingFormProps> = ({ onBack, onSuccess, session, isDemoMode }) => {
  const [itemName, setItemName] = useState('');
  const [brand, setBrand] = useState('');
  const [size, setSize] = useState('');
  const [gender, setGender] = useState<'Mens' | 'Womens' | 'Unisex'>('Unisex');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const genders = ['Mens', 'Womens', 'Unisex'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, reader.result as string].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file as any);
    });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName || !price || photos.length === 0) {
      return alert(photos.length === 0 ? 'Please upload at least one photo' : 'Please fill in required fields');
    }

    if (isDemoMode) {
      alert('You are in Demo/Guest mode! Please sign up with a real account to save items to the cloud.');
      return;
    }

    setIsSubmitting(true);

    try {
      const imageUrlData = photos.length > 1 ? JSON.stringify(photos) : photos[0];

      const { error } = await supabase.from('listings').insert([
        {
          title: itemName,
          brand,
          size,
          gender,
          price: parseFloat(price),
          condition,
          category: 'Clothing',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;

      alert('Item posted successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      alert(err.message || 'Something went wrong.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-orange-600 p-6 flex items-start space-x-4 text-white pt-14">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h1 className="text-xl font-black uppercase tracking-tight">List Clothing</h1>
          <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest">Campus Marketplace</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-32 no-scrollbar">
        <div className="space-y-3">
          <label className="text-xs font-black text-gray-400 uppercase tracking-widest flex justify-between">
            <span>Photos *</span>
            <span>{photos.length}/{MAX_PHOTOS}</span>
          </label>

          <div className="flex space-x-3 overflow-x-auto no-scrollbar pb-2">
            {photos.map((photo, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={photo} className="w-28 h-28 rounded-3xl object-cover border border-gray-100 shadow-sm" alt="Preview" />
                <button 
                  onClick={() => removePhoto(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg border-2 border-white active:scale-90 transition-transform"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            ))}

            {photos.length < MAX_PHOTOS && (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-28 h-28 rounded-3xl border-2 border-dashed border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 hover:bg-white hover:border-orange-300 transition-all flex-shrink-0 group"
              >
                <div className="bg-white p-2 rounded-xl shadow-sm mb-1 group-hover:scale-110 transition-transform">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <span className="text-[9px] font-black uppercase tracking-tighter">Add</span>
              </button>
            )}
          </div>
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" multiple className="hidden" />
        </div>

        <div className="space-y-5">
          <div className="space-y-1">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Item Name *</label>
            <input 
              type="text" 
              value={itemName}
              onChange={(e) => setItemName(e.target.value)}
              placeholder="UTD Hoodie" 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all text-sm font-bold" 
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Brand</label>
              <input 
                type="text" 
                value={brand}
                onChange={(e) => setBrand(e.target.value)}
                placeholder="Nike, Champion" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all text-sm font-bold" 
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Size</label>
              <input 
                type="text" 
                value={size}
                onChange={(e) => setSize(e.target.value)}
                placeholder="S, M, L, XL" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none transition-all text-sm font-bold" 
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Gender</label>
            <div className="flex gap-2">
              {genders.map((g) => (
                <button
                  key={g}
                  onClick={() => setGender(g as any)}
                  className={`flex-1 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${gender === g ? 'bg-orange-600 text-white shadow-lg' : 'bg-gray-50 text-gray-400 border border-gray-100'}`}
                >
                  {g}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Price ($) *</label>
              <input 
                type="number" 
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                placeholder="0.00" 
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none text-sm font-bold" 
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Pickup *</label>
              <select 
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 appearance-none outline-none text-sm font-bold"
              >
                {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Description</label>
            <textarea 
              rows={4}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Tell other students about this item..." 
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none resize-none text-sm font-medium leading-relaxed"
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Condition *</label>
            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button
                  key={c}
                  onClick={() => setCondition(c)}
                  className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${condition === c ? 'bg-orange-600 text-white shadow-lg shadow-orange-100 scale-105' : 'bg-gray-50 text-gray-400 border border-gray-100'}`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        </div>

        <button 
          onClick={handleSubmit}
          disabled={isSubmitting}
          className={`w-full text-white font-black py-5 rounded-[2rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-widest text-sm mt-4 ${
            isDemoMode ? 'bg-gray-400 cursor-not-allowed' : 'bg-orange-600 shadow-orange-100 hover:bg-orange-700'
          }`}
        >
          {isSubmitting ? 'Posting...' : isDemoMode ? 'Sign in to Post' : 'Post Clothing Item'}
        </button>
      </div>
    </div>
  );
};

export default ClothingListingForm;

import React, { useState, useMemo } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  isDemoMode: boolean;
  onBack: () => void;
  onMessage: () => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, isDemoMode, onBack, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isMessaging, setIsMessaging] = useState(false);

  const isOwner = session?.user?.id === item.seller_id;

  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try {
      if (item.image_url.startsWith('[') && item.image_url.endsWith(']')) {
        return JSON.parse(item.image_url) as string[];
      }
      return [item.image_url];
    } catch (e) {
      return [item.image_url];
    }
  }, [item.image_url]);

  const handleNext = () => setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  const handlePrev = () => setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);

  const handleMessageSeller = async () => {
    if (isDemoMode) {
      alert("Direct Messaging requires a real account. Please sign up!");
      return;
    }

    setIsMessaging(true);
    try {
      // 1. Try to find existing conversation
      const { data: existing, error: findError } = await supabase
        .from('conversations')
        .select('id')
        .eq('listing_id', item.id)
        .eq('buyer_id', session.user.id)
        .single();

      if (findError && findError.code !== 'PGRST116') {
        if (findError.code === '42P01') {
          alert('DM feature is not set up in the database. Run the SQL script from the Inbox tab.');
          return;
        }
        throw findError;
      }

      if (existing) {
        onMessage();
        return;
      }

      // 2. Create new conversation
      const { error: createError } = await supabase
        .from('conversations')
        .insert({
          listing_id: item.id,
          buyer_id: session.user.id,
          seller_id: item.seller_id
        });

      if (createError) throw createError;
      onMessage();
    } catch (err: any) {
      console.error('Error starting chat:', err);
      alert('Could not start chat: ' + (err.message || 'Unknown error'));
    } finally {
      setIsMessaging(false);
    }
  };

  const handleDelete = async () => {
    if (isDemoMode) {
      alert("Guest accounts can't delete items.");
      return;
    }
    if (!window.confirm('Are you sure you want to remove this listing?')) return;

    setIsDeleting(true);
    try {
      const { data, error } = await supabase
        .from('listings')
        .delete()
        .eq('id', item.id)
        .select();

      if (error) throw error;
      if (!data || data.length === 0) {
        alert('Permission denied or item already removed.');
        onBack();
        return;
      }
      alert('Listing successfully removed.');
      onBack();
    } catch (err: any) {
      alert('Error deleting item: ' + err.message);
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar animate-in slide-in-from-bottom duration-300">
      <div className="relative w-full aspect-[4/3] bg-gray-50 flex items-center justify-center p-8">
        <button onClick={onBack} className="absolute top-12 left-6 z-30 bg-white/90 backdrop-blur p-2.5 rounded-2xl shadow-xl border border-gray-100">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        <div className="w-full h-full relative group">
          <img src={photos[currentPhotoIdx]} alt={item.title} className="w-full h-full object-contain mix-blend-multiply" />
          {photos.length > 1 && (
            <>
              <button onClick={handlePrev} className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-r-xl opacity-0 group-hover:opacity-100 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
              </button>
              <button onClick={handleNext} className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/40 p-2 rounded-l-xl opacity-0 group-hover:opacity-100 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
              </button>
            </>
          )}
        </div>
      </div>

      <div className="px-6 pb-24 pt-6">
        <div className="flex justify-between items-start mb-6">
          <div className="flex-1 pr-4">
            <h1 className="text-2xl font-bold text-gray-900 leading-tight mb-1">{item.title}</h1>
            <span className="text-sm font-bold text-orange-600 uppercase tracking-tighter">{item.brand}</span>
          </div>
          <div className="border-2 border-orange-100 rounded-[1.25rem] px-4 py-2 bg-white shadow-sm">
            <span className="text-xl font-black text-orange-600">${Number(item.price).toFixed(2)}</span>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 mb-6">
          <div className="bg-orange-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Condition</p>
            <p className="text-sm font-bold text-orange-600">{item.condition}</p>
          </div>
          <div className="bg-emerald-50/50 p-4 rounded-[1.5rem]">
            <p className="text-[10px] uppercase font-bold text-gray-400">Category</p>
            <p className="text-sm font-bold text-emerald-600">{item.category}</p>
          </div>
        </div>

        {/* Dynamic Detail Badges (Size & Gender) */}
        {(item.size || item.gender) && (
          <div className="grid grid-cols-2 gap-3 mb-6">
            {item.size && (
              <div className="bg-purple-50/50 border border-purple-100 rounded-[1.5rem] p-4 flex items-center space-x-3">
                <div className="bg-purple-100 p-2 rounded-xl">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-purple-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                  </svg>
                </div>
                <div>
                  <p className="text-[10px] uppercase font-bold text-gray-400">Size</p>
                  <p className="text-sm font-bold text-purple-600">{item.size}</p>
                </div>
              </div>
            )}
            {item.gender && (
              <div className="bg-blue-50/50 border border-blue-100 rounded-[1.5rem] p-4 flex items-center space-x-3">
                <div className="bg-blue-100 p-2 rounded-xl">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                  </svg>
                </div>
                <div>
                  <p className="text-[10px] uppercase font-bold text-gray-400">Gender</p>
                  <p className="text-sm font-bold text-blue-600">{item.gender}</p>
                </div>
              </div>
            )}
          </div>
        )}

        <div className="bg-emerald-50/30 border border-emerald-100 rounded-[1.5rem] p-4 mb-6 flex items-center space-x-3">
          <div className="bg-orange-100 p-2.5 rounded-2xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-orange-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            </svg>
          </div>
          <div><p className="text-[10px] uppercase font-bold text-gray-400">Pickup</p><p className="text-sm font-bold text-orange-600">{item.location}</p></div>
        </div>

        {/* Item Description Section - Fixed to ensure it's displayed */}
        {item.description && (
          <div className="mb-8 p-5 bg-gray-50/50 rounded-[2rem] border border-gray-100">
            <p className="text-[10px] uppercase font-black text-gray-400 tracking-widest mb-2">Description</p>
            <p className="text-sm text-gray-700 leading-relaxed whitespace-pre-wrap font-medium">
              {item.description}
            </p>
          </div>
        )}

        <div className="bg-gray-50/50 border border-gray-100 rounded-[2rem] p-5 space-y-5">
          <div className="flex items-center space-x-4">
            <img 
              src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${item.seller_id}`} 
              className="w-14 h-14 rounded-2xl bg-orange-100 border border-orange-200" 
              alt="Seller"
            />
            <div>
              <h4 className="font-bold text-gray-900">Campus Seller</h4>
              <p className="text-xs text-gray-400 font-medium">Verified Student</p>
            </div>
          </div>

          {isOwner ? (
            <button 
              onClick={handleDelete} 
              disabled={isDeleting} 
              className="w-full bg-red-50 py-4 rounded-2xl flex items-center justify-center space-x-2 text-red-600 font-bold active:scale-95 transition-all"
            >
              <span className="text-sm">{isDeleting ? 'Removing...' : 'Delete Listing'}</span>
            </button>
          ) : (
            <button 
              onClick={handleMessageSeller} 
              disabled={isMessaging}
              className="w-full bg-orange-600 shadow-xl shadow-orange-100 py-4 rounded-2xl flex items-center justify-center space-x-2 text-white font-bold active:scale-95 transition-all hover:bg-orange-700"
            >
              <span className="text-sm">{isMessaging ? 'Connecting...' : 'Message Seller'}</span>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default ItemDetail;

import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  onSelectItem?: (item: any) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ onSelectItem }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [listings, setListings] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing' | 'other'>('none');

  const categories = [
    { name: 'Clothing', icon: '­¤æĢ' },
    { name: 'Furniture', icon: '­¤¬æ' },
    { name: 'Electronics', icon: '­¤Æ╗' }
  ];

  const setupSQL = `
-- Create the main listings table with all required fields
create table if not exists public.listings (
  id uuid default gen_random_uuid() primary key,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  title text not null,
  brand text,
  size text,
  gender text,
  price numeric not null,
  condition text not null,
  category text not null,
  location text not null,
  description text,
  image_url text,
  seller_id uuid not null default auth.uid()
);

-- Enable Security
alter table public.listings enable row level security;

-- Policies
create policy "Anyone can view listings" on public.listings for select using (true);
create policy "Users can add items" on public.listings for insert with check (auth.uid() = seller_id);
create policy "Users can delete their items" on public.listings for delete using (auth.uid() = seller_id);
  `.trim();

  useEffect(() => {
    fetchListings();

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-realtime')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => {
          fetchListings();
        })
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, []);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === '42P01') setErrorType('table_missing');
        else setErrorType('other');
        throw error;
      }

      if (data) {
        setListings(data);
        setErrorType('none');
      }
    } catch (err: any) {
      console.error('Fetch error:', err.message);
    } finally {
      setLoading(false);
    }
  };

  const displayedItems = listings.filter(item => item.category === activeCategory);

