            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.5rem] text-sm shadow-sm ${
                  isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-12 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-2">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Type a message..." 
              className="flex-1 bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-orange-100 transition-all"
            />
            <button 
              onClick={handleSendMessage} 
              className="bg-orange-500 text-white p-3.5 rounded-2xl shadow-lg shadow-orange-100 active:scale-90 transition-transform"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-16 pb-6 px-8 border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Inbox</h1>
        <div className="flex items-center space-x-2 mt-1">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Campus Live</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-24 p-4 space-y-3 bg-gray-50/30">
        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : conversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 text-center px-8">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 mb-6 opacity-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <h3 className="text-gray-900 font-bold mb-1 uppercase tracking-tighter text-lg">No Messages Yet</h3>
            <p className="text-xs font-medium text-gray-400">Items you message sellers about will appear here.</p>
          </div>
        ) : (
          conversations.map((chat) => (
            <div 
              key={chat.id} 
              onClick={() => setSelectedConversation(chat)}
              className="p-5 flex items-center space-x-5 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:border-orange-100"
            >
              <div className="relative">
                <img 
                  src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${chat.other_user_id}`} 
                  className="w-16 h-16 rounded-[1.5rem] bg-orange-50 border border-orange-100" 
                  alt="Avatar" 
                />
                <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 border-2 border-white rounded-full"></div>
              </div>
              <div className="flex-1">
                <h3 className="font-black text-gray-900 text-lg tracking-tight mb-0.5">
                  {getUserHandle(chat.other_user_id)}
                </h3>
              </div>
              <div className="text-gray-200">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                </svg>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState, useEffect } from 'react';
import { Tab, Category } from './types';
import Navigation from './components/Navigation';
import SellFlow from './components/SellFlow';
import Profile from './components/Profile';
import Marketplace from './components/Marketplace';
import Messages from './components/Messages';
import ItemDetail from './components/ItemDetail';
import Login from './components/Login';
import { supabase, isSupabaseConfigured } from './lib/supabase';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [viewingItem, setViewingItem] = useState<any>(null);
  const [isDemoMode, setIsDemoMode] = useState(!isSupabaseConfigured);
  const [unreadCount, setUnreadCount] = useState(0);
  const [lastNotification, setLastNotification] = useState<string | null>(null);

  useEffect(() => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) setIsDemoMode(false);
      else setIsDemoMode(!isSupabaseConfigured);
    });

    return () => subscription.unsubscribe();
  }, []);

  // Global message listener for notifications and unread badge
  useEffect(() => {
    if (!session?.user?.id || isDemoMode) return;

    const channel = supabase
      .channel('global-notifications')
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: 'public', 
        table: 'messages' 
      }, async (payload) => {
        const newMessage = payload.new;

        // Only notify if someone else sent the message
        if (newMessage.sender_id !== session.user.id) {
          // Check if the message is for a conversation I am part of
          const { data: conv } = await supabase
            .from('conversations')
            .select('id, buyer_id, seller_id')
            .eq('id', newMessage.conversation_id)
            .single();

          if (conv && (conv.buyer_id === session.user.id || conv.seller_id === session.user.id)) {
            // Increment unread if not currently looking at messages
            if (activeTab !== Tab.MESSAGES) {
              setUnreadCount(prev => prev + 1);
              setLastNotification(newMessage.text);
              // Clear banner after 3 seconds
              setTimeout(() => setLastNotification(null), 3000);
            }
          }
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [session?.user?.id, activeTab, isDemoMode]);

  useEffect(() => {
    // Reset unread count when entering messages tab
    if (activeTab === Tab.MESSAGES) {
      setUnreadCount(0);
    }
  }, [activeTab]);

  const handleDemoLogin = () => {
    setIsDemoMode(true);
    setSession({ user: { email: 'demo@utdallas.edu', id: 'demo-user' } });
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="flex flex-col items-center space-y-4">
          <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-orange-600 font-bold animate-pulse tracking-tighter text-xl">Hucksta</p>
        </div>
      </div>
    );
  }

  if (!session) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white shadow-2xl rounded-[3rem] overflow-hidden min-h-[852px]">
          <Login onLogin={handleDemoLogin} />
          {!isSupabaseConfigured && (
            <div className="px-8 pb-8 -mt-8 text-center">
              <p className="text-[10px] text-gray-400 mb-2 italic">Backend not connected yet.</p>
              <button 
                onClick={handleDemoLogin}
                className="text-xs font-bold text-orange-600 underline"
              >
                Enter Demo Mode (No Setup Required)
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (viewingItem) {
      return (
        <ItemDetail 
          item={viewingItem} 
          session={session}
          isDemoMode={isDemoMode}
          onBack={() => setViewingItem(null)} 
          onMessage={() => {
            setViewingItem(null);
            setActiveTab(Tab.MESSAGES);
          }}
        />
      );
    }

    switch (activeTab) {
      case Tab.HOME:
        return <Marketplace onSelectItem={setViewingItem} />;
      case Tab.MESSAGES:
        return <Messages session={session} isDemoMode={isDemoMode} />;
      case Tab.SELL:
        return (
          <SellFlow 
            category={selectedCategory} 
            onSelectCategory={setSelectedCategory} 
            session={session}
            isDemoMode={isDemoMode}
            onCancel={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
            onSuccess={() => {
              setSelectedCategory(null);
              setActiveTab(Tab.HOME);
            }}
          />
        );
      case Tab.PROFILE:
        return <Profile session={session} onSelectItem={setViewingItem} />;
      default:
        return <Marketplace onSelectItem={setViewingItem} />;
    }
  };

  return (
    <div className="min-h-screen pb-20 bg-gray-50">
      <div className="max-w-md mx-auto relative min-h-screen bg-white shadow-xl overflow-hidden">
        {/* Notification Banner */}
        {lastNotification && (
          <div className="absolute top-14 left-4 right-4 z-[100] animate-in slide-in-from-top duration-300">
            <div className="bg-orange-600 text-white px-6 py-4 rounded-3xl shadow-2xl flex items-center space-x-4 border border-white/20 backdrop-blur-md">
              <div className="bg-white/20 p-2 rounded-xl">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                </svg>
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/70">New Message</p>
                <p className="text-sm font-bold truncate">{lastNotification}</p>
              </div>
              <button onClick={() => setLastNotification(null)} className="text-white/50">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          </div>
        )}

        {renderContent()}

        <Navigation 
          activeTab={activeTab} 
          unreadCount={unreadCount}
          onTabChange={(tab) => {
            setActiveTab(tab);
            if (tab !== Tab.SELL) setSelectedCategory(null);
            setViewingItem(null);
          }} 
        />
      </div>
    </div>
  );
};

export default App;

