              <p className={`text-xs font-bold ${isSupabaseConfigured ? 'text-emerald-600' : 'text-orange-600'}`}>
                {isSupabaseConfigured ? 'Supabase Connected' : 'Demo Mode (Offline)'}
              </p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Active Listings</p>
