        <div className="relative z-10 flex flex-col items-center">
          <h1 className="text-6xl font-black text-white tracking-tighter drop-shadow-lg mb-2">Hucksta</h1>
          <div className="flex items-center space-x-2 bg-black/10 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/20">
            <div className={`w-2 h-2 rounded-full ${errorType === 'none' ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></div>
            <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">
              {errorType === 'none' ? 'UTD Campus Live' : 'Action Required'}
            </span>
          </div>
        </div>
      </div>

      {errorType === 'table_missing' ? (
        <div className="flex-1 p-6 -mt-8">
          <div className="bg-white rounded-[3rem] p-10 shadow-2xl flex flex-col items-center text-center space-y-6 border border-gray-100">
            <div className="w-20 h-20 bg-orange-50 rounded-full flex items-center justify-center text-orange-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" />
