        {
          title: itemName,
          brand,
          size,
          gender,
          price: parseFloat(price),
          condition,
          category: 'Clothing',
          location,
          description,
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) throw error;

      setIsSuccess(true);
      setTimeout(() => {
        onSuccess?.();
      }, 2000);
    } catch (err: any) {
      console.error('Submit Error:', err.message || err);
      alert('Post failed: ' + (err.message || 'Check your database connection.'));
    } finally {
      setIsSubmitting(false);
    }
