              <div 
                key={item.id} 
                onClick={() => onSelectItem?.(item)}
                className="bg-white rounded-3xl p-1.5 border border-gray-100 flex flex-col h-full transform active:scale-95 transition-transform cursor-pointer shadow-sm"
              >
                <div className="relative aspect-[4/5] rounded-2xl overflow-hidden mb-2">
                  <img src={getThumbnail(item.image_url)} alt={item.title} className="w-full h-full object-cover" />
                  <div className="absolute top-2 left-2 px-2 py-1 rounded-lg text-[8px] font-black text-white bg-black/50 backdrop-blur-sm uppercase tracking-widest">
                    {item.condition}
                  </div>
                </div>

                <div className="px-2 pb-2">
                  {item.brand && (
                    <p className="text-[8px] font-black text-orange-600 uppercase tracking-widest mb-0.5 truncate">
                      {item.brand}
                    </p>
                  )}
                  <h3 className="font-bold text-gray-900 text-[11px] leading-tight mb-1 line-clamp-2 h-6">{item.title}</h3>
                  <div className="flex items-center justify-between mt-auto">
                    <p className="text-orange-600 font-black text-sm">${Number(item.price).toFixed(2)}</p>
                    <span className="text-[8px] text-gray-400 font-bold uppercase tracking-tighter truncate max-w-[60px]">{item.location}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

